import { Disease, DiseaseCategory } from '../types';
const DISEASE_CATEGORIES: Record<DiseaseCategory, { label: string; icon: string; color: string }> = { infectious: { label: 'Infecciosas', icon: 'virus', color: '#E53935' }, parasitic: { label: 'Parasitarias', icon: 'bug-outline', color: '#8E24AA' }, degenerative: { label: 'Degenerativas', icon: 'trending-down', color: '#F57C00' }, oncological: { label: 'Oncologicas', icon: 'alert-circle', color: '#C62828' }, nutritional: { label: 'Nutricionales', icon: 'nutrition', color: '#43A047' }, autoimmune: { label: 'Autoinmunes', icon: 'shield', color: '#1565C0' }, traumatic: { label: 'Traumaticas', icon: 'bandage', color: '#6D4C41' }, congenital: { label: 'Congenitas', icon: 'dna', color: '#00838F' }, respiratory: { label: 'Respiratorias', icon: 'lungs', color: '#26A69A' }, gastrointestinal: { label: 'Gastrointestinales', icon: 'stomach', color: '#7CB342' }, dermatological: { label: 'Dermatologicas', icon: 'hand-heart', color: '#EC407A' }, ocular: { label: 'Oculares', icon: 'eye', color: '#5C6BC0' }, dental: { label: 'Dentales', icon: 'tooth', color: '#78909C' }, endocrine: { label: 'Endocrinas', icon: 'flask', color: '#AB47BC' }, cardiovascular: { label: 'Cardiovasculares', icon: 'heart-pulse', color: '#E53935' }, neurological: { label: 'Neurologicas', icon: 'brain', color: '#7E57C2' }, musculoskeletal: { label: 'Musculoesqueleticas', icon: 'bone', color: '#8D6E63' }, renal: { label: 'Renales', icon: 'kidney', color: '#0097A7' }, reproductive: { label: 'Reproductivas', icon: 'baby-carriage', color: '#EC407A' }, toxic: { label: 'Toxicas', icon: 'skull', color: '#D32F2F' }, urological: { label: 'Urologicas', icon: 'kidney', color: '#00838F' }, };const DOG_DISEASES: Disease[] = [
  { id: 'Anaplasmosis-Canina', name: 'Anaplasmosis Canina', scientificName: 'Anaplasma phagocytophilum', species: 'dog', category: 'infectious', severity: 'moderate', description: 'Enfermedad vectorial transmitida por garrapatas. Afecta neutrófilos. Causa fiebre, dolor articular y trombocitopenia.', pathophysiology: 'El parásito invade neutrófilos causando activación plaquetaria. La trombocitopenia es por destrucción inmune mediada. La artritis inmunomediada causa dolor articular.', keySigns: ["Fiebre","Letargia","Dolor articular (poliartritis)","Cojera","Trombocitopenia","Petequias","Anorexia"], diagnosis: {"imaging":["Radiografía articulaciones: sin derrame"],"labTests":["ELISA SNAP 4Dx: detección de Anaplasma","PCR: confirmación molecular","Hemograma: trombocitopenia, leucopenia"],"clinicalExam":"Fiebre, dolor articular a la movilización, cojera, petequias","differentialDiagnosis":["Ehrlichiosis","Artritis inmunomediada","Lyme"]}, treatment: {"notes":"Chile: Doxiciclina disponible. SNAP 4Dx: disponible.","duration":"Antibioticoterapia 2-4 semanas.","firstLine":["Doxiciclina 10 mg/kg PO q12h por 2-4 semanas","AINEs: Carprofen 4.4 mg/kg PO q12h","Fluidoterapia si deshidratación"],"secondLine":["Imidocarb 6.6 mg/kg IM dosis única","Prednisona si artritis severa"]}, prevention: ["Prevención antiparasitaria","Evitar zonas con garrapatas","Inspección post-paseo"], prognosis: 'good', isZoonotic: false, references: ["ACVIM Anaplasmosis Guidelines 2024","JAVMA 2023;260(S1):S23-S35"] },
  { id: 'Babesiosis-Canina', name: 'Babesiosis Canina', scientificName: 'Babesia canis / B. gibsoni', species: 'dog', category: 'infectious', severity: 'severe', description: 'Enfermedad parasitaria transmitida por garrapatas. Los parásitos invaden y destruyen eritrocitos causando anemia hemolítica.', pathophysiology: 'Los trofozoítos invaden eritrocitos causando su destrucción. La hemólisis intravascular causa anemia severa, hemoglobinuria y falla renal.', keySigns: ["Fiebre","Anemia severa (mucosas pálidas/ictericia)","Hemoglobinuria (orina roja)","Esplenomegalia","Letargia","Anorexia","Taquicardia"], diagnosis: {"imaging":["Ecografía: esplenomegalia"],"labTests":["Frotis de sangre periférica: trofozoítos intraeritrocitarios","Hemograma: anemia regenerativa severa, trombocitopenia","Bioquímica: hiperbilirrubinemia"],"clinicalExam":"Fiebre, anemia severa, ictericia, esplenomegalia, orina oscura","differentialDiagnosis":["Ehrlichiosis","Anemia autoinmune","Intoxicación por cobre"]}, treatment: {"notes":"Chile: Imidocarb bajo importación. Bancos de sangre veterinarios en Santiago.","duration":"Hospitalización 3-7 días. Recuperación 2-4 semanas.","emergency":"Anemia severa con PCV \u003c12%: TRANSFUSIÓN INMEDIATA.","firstLine":["Imidocarb dipropionato 6.6 mg/kg IM dosis única","Transfusiones de sangre completa si PCV \u003c15%","Fluidoterapia IV","Prednisona 1-2 mg/kg PO q24h si anemia autoinmune"],"secondLine":["Atovaquona 13.5 mg/kg PO q12h + Azitromicina 10 mg/kg PO q24h (B. gibsoni)"]}, prevention: ["Prevención antiparasitaria estricta","Evitar zonas endémicas","Inspección diaria de garrapatas"], prognosis: 'guarded', isZoonotic: false, references: ["ACVIM Babesiosis Guidelines 2023","JAVMA 2024;265(3):310-322"] },
  { id: 'Dermatitis-Atpica-Canina', name: 'Dermatitis Atópica Canina', scientificName: 'Canine Atopic Dermatitis (CAD)', species: 'dog', category: 'dermatological', severity: 'moderate', description: 'Enfermedad inflamatoria alérgica de la piel. Predispuesta genéticamente. Reacción a alérgenos ambientales (polvo, ácaros, pólenes).', pathophysiology: 'La barrera cutánea defectuosa permite entrada de alérgenos. Los mastocitos liberan histamina e IL-31 causando prurito. La respuesta Th2 dominante perpetúa la inflamación. La sobreinfección bacteriana/fúngica empeora los signos.', keySigns: ["Prurito intenso (cara, patas, axilas, ingles)","Eritema","Excoriaciones","Liquenificación","Hiperpigmentación","Otitis externa recurrente","Dermatitis podal"], diagnosis: {"imaging":[],"labTests":["Citología cutánea: sobreinfección bacteriana/fúngica","Swab cutáneo: Staphylococcus pseudintermedius","Trichograma: descartar ácaros","Serología alérgena (IgE)"],"clinicalExam":"Prurito \u003e5/10, distribución facial/patas/axilas/ingles, eritema, excoriaciones, liquenificación","differentialDiagnosis":["Dermatitis alérgica a pulgas","Dermatofitosis","Sarna demodécica","Dermatitis por contacto"]}, treatment: {"notes":"Chile: Apoquel® (Zoetis), Cytopoint® (Zoetis), Atopica® (Zoetis) disponibles. Dietas: Hill derma, Royal Canin Skin Support.","duration":"Tratamiento de por vida. Apoquel: respuesta 24-48h. Cytopoint: 1-3 días.","emergency":"Dermatitis aguda severa: Prednisona 1-2 mg/kg PO + antibiótico + collar isabelino.","firstLine":["Oclacitinib (Apoquel®) 0.4-0.6 mg/kg PO q12h × 14 días luego q24h","Prednisona 0.5-1 mg/kg PO q24h tapering","Cetirizina 5-10 mg PO q12-24h","Baños terapéuticos con clorhexidina/miconazol","Cefalexina 22 mg/kg PO q12h si sobreinfección"],"secondLine":["Ciclosporina (Atopica®) 5 mg/kg PO q24h","Lokivetmab (Cytopoint®) 0.4-1.0 mg/kg SC q4-8w","Suplementación omega-3"]}, prevention: ["Control de pulgas estricto","Baños terapéuticos semanales","Suplementación omega-3","Control de ambiente (antialérgicos de cama)"], prognosis: 'guarded', isZoonotic: false, references: ["ISCM Consensus CAD 2024","ACVIM Atopic Dermatitis Guidelines 2023","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Dermatofitosis-Canina', name: 'Dermatofitosis Canina', scientificName: 'Dermatophytosis (Microsporum canis/gypseum)', species: 'dog', category: 'dermatological', severity: 'mild', description: 'Infección fúngica de la piel, pelo y uñas causada por dermatofitos. Enfermedad zoonótica.', pathophysiology: 'Los dermatofitos invaden el folículo piloso y la capa córnea. La queratina del pelo es degradada por enzimas fúngicas. La respuesta inflamatoria causa prurito variable.', keySigns: ["Lesiones circulares alopecicas","Costras y escamas","Eritema periférico","Pérdida de pelo en parches","Picazón variable","Lesiones en orejas, cara, patas"], diagnosis: {"imaging":[],"labTests":["Lámpara de Wood: fluorescencia (50% M. canis)","Raspado de piel + KOH: hifas","Cultivo en agar Sabouraud: 7-21 días","PCR para especie de dermatofito"],"clinicalExam":"Lesiones alopecicas redondeadas, costras, distribución en cara y patas","differentialDiagnosis":["Dermatitis alérgica","Sarna","Dermatitis miliar","Alopecia psicogénica"]}, treatment: {"notes":"Chile: Itraconazol y Terbinafina disponibles en farmacias (compounding).","duration":"Hasta 2 cultivos negativos consecutivos. Promedio 6-8 semanas.","emergency":"No hay emergencia específica.","firstLine":["Itraconazol 5 mg/kg PO q24h por 6-8 semanas","Terbinafina 30 mg/kg PO q24h por 6 semanas","Shampoo con clorhexidina/miconazol 2×/semana","Limpiar ambiente: lavar camas, aspirar","Tratar todos los animales del hogar"],"secondLine":["Enilconazol tópico","Micafungina"]}, prevention: ["Aislamiento de animales infectados","Desinfección del ambiente","Exámenes dermatológicos regulares","Buen estado nutricional e inmune"], prognosis: 'excellent', isZoonotic: true, references: ["Moriello KA, et al. Greene CE, ed. 4th ed. Elsevier; 2012","AAFP - Dermatophytosis Guidelines"] },
  { id: 'Diabetes-Mellitus-Canino', name: 'Diabetes Mellitus Canino', scientificName: 'Diabetes Mellitus - Canine', species: 'dog', category: 'endocrine', severity: 'moderate', description: 'Deficiencia de insulina o resistencia a la insulina. Causa hiperglucemia persistente. Puede progresar a cetoacidosis diabética. Más común en perros >7 años, hembras no castradas.', pathophysiology: 'Las células beta pancreáticas destruidas no producen suficiente insulina. Sin insulina, la glucosa no ingresa a las células causando hiperglucemia. La lipólisis descontrolada produce cuerpos cetónicos (cetoacidosis).', keySigns: ["Poliuria/polidipsia","Pérdida de peso con buena ingesta","Anorexia","Vómitos","Cataratas bilaterales","Letargia","Orina pegajosa"], diagnosis: {"imaging":["Ecografía abdominal: páncreas, excluir masas"],"labTests":["Glucemia en ayuno \u003e250 mg/dL","Glucosuria persistente","Fructosamina \u003e400 µmol/L","Cetonuria en cetoacidosis"],"clinicalExam":"Pérdida de peso, cataratas bilaterales (50%), hepatomegalia, deshidratación, aliento con olor a acetona","differentialDiagnosis":["Hiperglucemia estresante","Enfermedad de Cushing","Pancreatitis"]}, treatment: {"notes":"Chile: Humulin N® (Eli Lilly), Lantus® (Sanofi) disponibles. Dietas: Hills, Royal Canin disponibles.","duration":"Tratamiento de por vida. Regulación inicial: 1-2 meses. Monitoreo de fructosamina cada 3-6 meses.","emergency":"Cetoacidosis: fluidoterapia 0.9% NaCl 90 mL/kg/h + insulina regular IV 0.1 UI/kg carga + bicarbonato si pH \u003c7.1.","firstLine":["Insulina NPH (Humulin N®) 0.25-0.5 UI/kg SC q12h","Dieta: Hills w/d, Royal Canin W/S — bajo carbohidratos","Monitoreo de glucemia en casa","Metformina 10-25 mg/kg PO q12h"],"secondLine":["Insulina Glargina (Lantus®) 1-2 UI/kg SC q24h","Pimobendan (Vetmedin®) 0.25 mg/kg PO q12h","Ursodiol (Ursacol®) 10-15 mg/kg PO q12h"]}, prevention: ["Castración de hembras (reduce resistencia a insulina)","Mantener peso corporal ideal","Dieta baja en carbohidratos","Ejercicio regular y consistente"], prognosis: 'good', isZoonotic: false, references: ["ACVIM Canine Diabetes Consensus 2023","JAVMA 2024;264(3):310-320","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Displasia-Coxofemoral', name: 'Displasia Coxofemoral', scientificName: 'Canine Hip Dysplasia (CHD)', species: 'dog', category: 'musculoskeletal', severity: 'moderate', description: 'Enfermedad degenerativa multifactorial de la articulación coxofemoral. El acetábulo y la cabeza femoral no encajan correctamente, provocando laxitud articular, osteoartritis y dolor crónico.', pathophysiology: 'La laxitud articular permite movimiento anormal de la cabeza femoral respecto al acetábulo. Esto causa erosión del cartílago articular y formación de osteofitos. La inflamación crónica provoca fibrosis de la cápsula articular.', keySigns: ["Cojera de extremidades posteriores (bilateral)","Dificultad para levantarse","Caminata de conejo","Resistencia al ejercicio","Dolor a la manipulación de caderas","Atrofia muscular de muslos"], diagnosis: {"imaging":["Radiografía bajo sedación: posición ventrodorsal extendida","Clasificación OFA/FCI"],"labTests":["No hay pruebas de laboratorio específicas"],"clinicalExam":"Prueba de Ortolani positiva, dolor a la extensión/flexión de cadera, atrofia de músculos glúteos","differentialDiagnosis":["Osteocondritis disecante","Enfermedad de Legg-Calvé-Perthes","Ruptura de ligamento cruzado"]}, treatment: {"notes":"Chile: Rimadyl® (Zoetis), Meloxicam genéricos. Cirugía de cadera: clínicas especializadas Santiago, Concepción.","duration":"Manejo de por vida. Cirugía: recuperación 8-12 semanas.","emergency":"Crisis de dolor agudo: AINEs parenterales + analgesia multimodal.","firstLine":["Control de peso: mantener IMC ideal","Ejercicio controlado: natación, paseos cortos","AINEs: Carprofen 4.4 mg/kg PO q12-24h","Suplementos: Glucosamina/condroitina, omega-3","Fisioterapia y rehabilitación"],"secondLine":["Infiltración intraarticular con ácido hialurónico o PRP","Osteotomía pélvica","Escisión de cabeza y cuello femoral","Prótesis total de cadera"]}, prevention: ["Selección genética: evaluación padres antes de cría","Control nutricional en razas grandes","Evitar ejercicio excesivo en crecimiento","Suplementación con glucosamina","Mantenimiento de peso ideal"], prognosis: 'good', isZoonotic: false, references: ["OFA - Canine Hip Dysplasia Information","FCI Hip Dysplasia Grading System","JAVMA 2023;262(5):650-662"] },
  { id: 'Ehrlichiosis-Canina', name: 'Ehrlichiosis Canina', scientificName: 'Ehrlichia canis', species: 'dog', category: 'infectious', severity: 'severe', description: 'Enfermedad vectorial transmitida por garrapatas. Afecta neutrófilos, monocitos y plaquetas. Endémica en zonas tropicales y subtropicales.', pathophysiology: 'El parásito invade monocitos y neutrófilos causando destrucción celular. La inmunosupresión predispone a infecciones secundarias. La trombocitopenia causa hemorragias.', keySigns: ["Fiebre","Letargia","Anorexia","Pérdida de peso","Hemorragias petequiales","Epistaxis","Esplenomegalia","Edema de extremidades"], diagnosis: {"imaging":["Radiografía tórax: infiltrados pulmonares","Ecografía: esplenomegalia"],"labTests":["ELISA SNAP 4Dx: detección de Ehrlichia","PCR: confirmación molecular","Hemograma: trombocitopenia, leucopenia/leucocitosis, anemia","Citología: morulas intracelulares"],"clinicalExam":"Fiebre, letargia, esplenomegalia palpable, hemorragias petequiales, mucosas pálidas","differentialDiagnosis":["Anaplasmosis","Babesiosis","Leptospirosis"]}, treatment: {"notes":"Chile: Vibramycin® (Pfizer) disponible. SNAP 4Dx: veterinarias.","duration":"Antibioticoterapia 4-6 semanas.","emergency":"Trombocitopenia severa con sangrado: transfusión de plaquetas.","firstLine":["Doxiciclina (Vibramycin®) 10 mg/kg PO q12h por 4-6 semanas","Fluidoterapia si deshidratación","Transfusión de plaquetas si \u003c30,000/µL","Maropitant 1-2 mg/kg SC q24h","Omeprazol 1 mg/kg PO q24h"],"secondLine":["Imidocarb dipropionato 6.6 mg/kg IM dosis única","Cloranfenicol 25 mg/kg PO q12h"]}, prevention: ["Prevención antiparasitaria: fipronil, permetrina","Inspección diaria de garrapatas","Evitar zonas con pastizales altos","Tratamiento preventivo durante temporada"], prognosis: 'guarded', isZoonotic: false, references: ["CVB - Ehrlichiosis Guidelines 2024","JAVMA 2023;262(8):1120-1130","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Enfermedad-de-Discos-Intervertebrales', name: 'Enfermedad de Discos Intervertebrales', scientificName: 'Intervertebral Disc Disease (IVDD)', species: 'dog', category: 'neurological', severity: 'moderate', description: 'Herniación o extrusión del núcleo pulposo del disco intervertebral. Común en razas braquicéfalas.', pathophysiology: 'El disco degenerado pierde hidratación y elasticidad. La extrusión comprime la médula espinal causando dolor, ataxia y parálisis.', keySigns: ["Dolor espinal","Ataxia de extremidades posteriores","Parálisis flácida progresiva","Incontinencia urinaria/fecal","Marcha hipermétrica","Incapacidad para caminar"], diagnosis: {"imaging":["Mielografía CT/MRI: GOLD STANDARD","Radiografía: espacio intervertebral estrecho"],"labTests":[],"clinicalExam":"Dolor espinal a la palpación, ataxia, parálisis, reflejos alterados","differentialDiagnosis":["Tumor espinal","Meningomielitis","Fibrocartilaginosa embolia"]}, treatment: {"notes":"Chile: Cirugía espinal en clínicas especializadas (Santiago, Concepción). Rehabilitación: centros de fisioterapia veterinaria.","duration":"Conservador: 4-6 semanas reposo. Cirugía: recuperación 6-8 semanas.","emergency":"Parálisis aguda con incontinencia: CIRUGÍA DE EMERGENCIA dentro de 24-48h.","firstLine":["GRADO I-II: reposo estricto 4-6 semanas","AINEs: Carprofen 4.4 mg/kg PO q12-24h","Analgesia: Gabapentina 5-10 mg/kg PO q8h","Grado III-IV: CIRUGÍA hemilaminectomía","Enfermería: movilización cada 4-6 horas"],"secondLine":["Acupuntura","Fisioterapia hidroterapia","Láser terapia"]}, prevention: ["Mantener peso ideal","Evitar saltos y escaleras en razas predisuestas","Camas orthopédicas","Ejercicio de bajo impacto"], prognosis: 'good', isZoonotic: false, references: ["ACVIM IVDD Guidelines 2024","JAVMA 2023;262(5):650-662"] },
  { id: 'Enfermedad-Periodontal', name: 'Enfermedad Periodontal', scientificName: 'Periodontal Disease', species: 'both', category: 'dental', severity: 'moderate', description: 'Inflamación y destrucción de tejidos de soporte dental. La enfermedad más común en perros y gatos >3 años.', pathophysiology: 'La placa bacteriana se acumula en la línea gingival. La respuesta inmune causa inflamación. La inflamación crónica destruye el ligamento periodontal y el hueso alveolar. Las bolsas periodontales se profundizan.', keySigns: ["Halitosis","Encías rojas/inflamadas","Sangrado gingival","Placa/tártaro visible","Dientes flojos","Pérdida de dientes","Dolor al masticar"], diagnosis: {"imaging":["Radiografía dental intraoral: estándar de oro"],"labTests":["Radiografía dental: pérdida de hueso alveolar, reabsorción radicular","Citología de bolsa: bacterias Gram+ y Gram-"],"clinicalExam":"Halitosis, gingivitis, sangrado al sondaje, bolsas periodontales \u003e3mm, tártaro, dientes moviles","differentialDiagnosis":["Estomatitis felina","Fractura dental","Neoplasia oral","Forl felino"]}, treatment: {"notes":"Chile: Clorhexidina 0.12% disponible. Rimadyl® (Zoetis), Antirobe® (Zoetis) disponibles.","duration":"Limpieza: recuperación 7-10 días. Mantenimiento: limpieza cada 6-12 meses.","emergency":"Absceso dental: drenaje + antibiótico IV. Celulitis facial: Amoxicilina-ácido clavulánico IV.","firstLine":["Limpieza dental profesional bajo anestesia general","Clindamicina (Antirobe®) 10 mg/kg PO q12h por 7-10 días","Clorhexidina 0.12% gel tópico gingival","Carprofen (Rimadyl®) 4.4 mg/kg PO q12h post-operatorio","Tramadol 2-5 mg/kg PO q8-12h"],"secondLine":["Amoxicilina-ácido clavulánico 12.5 mg/kg PO q12h","Doxiciclina 10 mg/kg PO q12h","Extracción de dientes comprometidos","Cirugía periodontal (injerto óseo)"]}, prevention: ["Cepillado diario con pasta dental veterinaria","Dietas VOHC aprobadas (Hills t/d, Royal Canin Dental)","Limpieza dental profesional anual","Chicles dentales aprobados"], prognosis: 'good', isZoonotic: false, references: ["AVDC Periodontal Disease Guidelines 2024","WSAVA Dental Guidelines 2023","JAVMA 2023;260(S1):S40-S52"] },
  { id: 'Enfermedad-Renal-Crnica-Perro', name: 'Enfermedad Renal Crónica (Perro)', scientificName: 'Chronic Kidney Disease (CKD) - Canine', species: 'dog', category: 'renal', severity: 'moderate', description: 'Pérdida progresiva e irreversible de función renal. IRIS staging I-IV. Más común en perros mayores (>7 años).', pathophysiology: 'La pérdida de nefronas funcionales obliga a las nefronas restantes a hiperfiltrar. La acumulación de toxinas urémicas causa daño multiorgánico. La eritropoyetina insuficiente causa anemia.', keySigns: ["Poliuria/polidipsia","Pérdida de peso","Anorexia","Vómitos","Halitosis urémica","Deshidratación","Piel seca","Anemia"], diagnosis: {"imaging":["Ecografía: riñones pequeños y fibrosados","Radiografía: riñones simétricos"],"labTests":["Creatinina \u003e1.6 mg/dL, SDMA \u003e18 µg/dL","BUN \u003e35 mg/dL","UAC: proteinuria \u003e0.5 g/día","Hemograma: anemia normocromica normocítica","Gasometría: acidosis metabólica"],"clinicalExam":"Pérdida de peso, deshidratación, halitosis urémica, mucosas pálidas, kidneys palpable增大 o disminuidos","differentialDiagnosis":["Nefritis intersticial","Nefropatía amiloidea","Pielonefritis","Insuficiencia cardíaca congestiva"]}, treatment: {"notes":"Chile: Hills k/d y Royal Canin Renal disponibles. EPO disponible en farmacias. Telmisartán (Semintra®) disponible.","duration":"Tratamiento de por vida. Monitoreo cada 3-6 meses. Estadio I-II: pronóstico bueno.","emergency":"Crisis urémica: fluidoterapia IV agresiva + bicarbonato si pH \u003c7.2. Convulsiones: Diazepam 0.5 mg/kg IV.","firstLine":["Dieta renal: Hills k/d, Royal Canin Renal","Fosfato de aluminio 30-60 mg/kg PO con comidas","Famotidina (Pepcid®) 0.5 mg/kg PO q12-24h","Eritropoyetina humana (EPO) 100-300 UI/kg SC 3×/semana","Fluidoterapia subcutánea 100-150 mL/q24-48h"],"secondLine":["Telmisartán (Semintra®) 1-2 mg/kg PO q24h","Calcitriol 2-3 ng/kg PO q24h","Maropitant (Cerenia®) 1 mg/kg SC q24h"]}, prevention: ["Dieta renal desde estadio IRIS II","Control de presión arterial anual en \u003e7 años","Evitar nefrotóxicos (AINE, aminoglucósidos)","Monitoreo de creatinina/SDMA cada 6 meses \u003e7 años"], prognosis: 'guarded', isZoonotic: false, references: ["IRIS CKD Staging Guidelines 2024","ACVIM Consensus Statement CKD 2023","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Envenenacin-por-Rodenticidas', name: 'Envenenación por Rodenticidas', scientificName: 'Anticoagulant Rodenticide Toxicosis', species: 'dog', category: 'toxic', severity: 'critical', description: 'Intoxicación por ingestion de rodenticidas anticoagulantes. Causa coagulopatía hemorrágica sistémica. Emergencia veterinaria común.', pathophysiology: 'Los rodenticidas inhiben la epoxido reductasa del vitamin K1. Esto impide la síntesis de factores de coagulación II, VII, IX y X. La coagulopatía se manifiesta 2-5 días post-ingestión.', keySigns: ["Hemorragias múltiples: epistaxis, gingivorragia","Hematuria, melena","Equimosis subcutáneas","Debilidad","Disnea (hemotórax)","Colapso"], diagnosis: {"imaging":["Radiografía tórax: hemotórax","Ecografía: derrame libre"],"labTests":["TP y TPT prolongados \u003e2x control","INR elevado","Hemograma: anemia si sangrado activo","Factores de coagulación disminuidos"],"clinicalExam":"Hemorragias visibles, mucosas pálidas, taquicardia, hipotermia","differentialDiagnosis":["Coagulopatía por heparina","Trombocitopenia inmunomediada","Enfermedad hepática"]}, treatment: {"notes":"Chile: Vitamina K1 (Konakion®) disponible en farmacias. Antídoto altamente efectivo.","duration":"Vitamina K1 oral 4-6 semanas. Monitoreo de TP semanal.","emergency":"Sangrado masivo: TRANSFUSIÓN INMEDIATA + Vitamina K1 IV lento.","firstLine":["Vitamina K1 (fitomenadiona) 2.5-5 mg/kg PO/SC/IV — ANTIDOTO","Transfusiones de plasma fresco 10-20 mL/kg si sangrado activo","Transfusiones de sangre completa si PCV \u003c15%","Vitamin K1 oral por 4-6 semanas"],"secondLine":["Concentrado de complejo protrombínico"]}, prevention: ["Mantener rodenticidas fuera de alcance","Sellamiento de contenedores de basura","Alternativas no tóxicas para control de roedores"], prognosis: 'good', isZoonotic: false, references: ["ASPCA - Rodenticide Guidelines","JAVMA 2024;266(1):45-56","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Leishmaniasis', name: 'Leishmaniasis', scientificName: 'Leishmania infantum', species: 'dog', category: 'infectious', severity: 'severe', description: 'Enfermedad zoonótica transmitida por mosca psicófaga. El perro es principal reservorio. Formas cutánea y visceral.', pathophysiology: 'Los promastigotos son ingestidos por macrófagos donde se transforman a amastigotos. La replicación intracelular causa granulomas en piel, ganglios, hígado, riñones.', keySigns: ["Dermatitis exfolativa severa","Pérdida de pelo","Úlceras en orejas, nariz, patas","Onicogrifosis","Pérdida de peso","Linfadenopatía","Epistaxis","Uveítis"], diagnosis: {"imaging":["Radiografía: osteoartropatía hipertrofica"],"labTests":["Serología ELISA/IFAT","PCR en sangre o médula ósea","Citología: amastigotos intracelulares","Hemograma: anemia, trombocitopenia"],"clinicalExam":"Dermatitis exfolativa, úlceras, onicogrifosis, linfadenopatía generalizada","differentialDiagnosis":["Dermatitis alérgica","Dermatofitosis","Neoplasia cutárea"]}, treatment: {"notes":"Chile: Antimoniato bajo protocolo especial. Miltefosina: importación.","duration":"Tratamiento inicial 28-40 días. Supresión de por vida.","firstLine":["Antimoniato de meglumina 75-100 mg/kg SC q24h por 28-40 días","Miltefosina 2 mg/kg PO q24h por 28 días","Allopurinol 10 mg/kg PO q12h de por vida","Amoxicilina-ácido clavulánico 12.5 mg/kg PO q12h"],"secondLine":["Liposomal anfotericina B 3-5 mg/kg IV cada 48h","Domperidona 0.5 mg/kg PO q12h"]}, prevention: ["Prevención de picadura de mosca psicófaga","Moscqueros, repelentes","Viajeros a zonas endémicas: precaución"], prognosis: 'guarded', isZoonotic: true, references: ["WHO - Leishmaniasis Fact Sheet 2024","OIE/WOAH Leishmaniasis Code 2023"] },
  { id: 'Leptospirosis', name: 'Leptospirosis', scientificName: 'Leptospira interrogans', species: 'both', category: 'infectious', severity: 'severe', description: 'Enfermedad zoonótica causada por espiroquetas. Transmisión por contacto con orina de roedores o agua contaminada. Endémica en zonas urbanas de Chile.', pathophysiology: 'Las leptospiras ingresan por mucosas o piel herida. Se diseminan por bloodstream causando hepatitis infecciosa y nefritis intersticial. La lesión renal aguda es la principal causa de muerte.', keySigns: ["Fiebre alta","Ictericia","Poliuria/polidipsia","Vómitos","Dolor abdominal","Mialgia","Conjuntivitis","Hemorragias subcutáneas"], diagnosis: {"imaging":["Ecografía renal: riñones增大 e hiperecogénicos"],"labTests":["MAT: título \u003e1:800 diagnóstico","ELISA IgM: positivo en fase aguda","PCR en orina: positivo primeras 2 semanas","Hemograma: trombocitopenia, leucocitosis","Bioquímica: ALT/AST \u003e500 U/L, creatinina \u003e3.0 mg/dL"],"clinicalExam":"Fiebre 39.5-41°C, ictericia visible en mucosas, hepatomegalia dolorosa, mialgia severa","differentialDiagnosis":["Hepatitis infecciosa canina","Babesiosis","Intoxicación hepática","Pancreatitis aguda"]}, treatment: {"notes":"Chile: VIBRAMYCIN® (Pfizer). ZONA ENDÉMICA: Santiago, Valparaíso, Concepción. ZOONOSIS: handlers deben usar guantes.","duration":"Antibioticoterapia 2-4 semanas. Recuperación renal 2-4 semanas.","emergency":"Fallo renal agudo: fluidoterapia agresiva + diálisis peritoneal si oliguria. TROMBOCITOPENIA: evitar procedimientos invasivos.","firstLine":["Doxiciclina (Vibramycin®) 10 mg/kg PO q12h por 2-4 semanas","Penicilina G cristalina 22,000-44,000 UI/kg IV q6h","Fluidoterapia: Ringer Lactato 60-80 mL/kg/día","Maropitant (Cerenia®) 1-2 mg/kg SC q24h","Famotidina (Pepcid®) 0.5 mg/kg IV q12h"],"secondLine":["Ampicilina 22 mg/kg IV q6h","Ceftriaxona 25-50 mg/kg IV q24h","N-acetilcisteína (Fluimucil®) 140 mg/kg IV carga","Transfusión de plaquetas si \u003c30,000/µL"]}, prevention: ["Vacunación Lepto anual (Nobivac L4 o Leptoguard)","Control de roedores en predios","Evitar contacto con agua stagnante/charcos","Notificación obligatoria al SEREMI de Salud"], prognosis: 'guarded', isZoonotic: true, references: ["ACVIM Consensus Statement Leptospirosis 2023","WSAVA Vaccination Guidelines 2024","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Linfoma-Canino', name: 'Linfoma Canino', scientificName: 'Canine Lymphoma', species: 'dog', category: 'oncological', severity: 'severe', description: 'Neoplasia del tejido linfático. Es el cáncer más común en perros. Formas: multicéntrica (80%), gastrointestinal, mediastínica, cutánea.', pathophysiology: 'La transformación maligna de linfocitos causa proliferación descontrolada. Los ganglios linfáticos se infiltran y增大. La diseminación por sistema linfático alcanza hígado, bazo y médula ósea.', keySigns: ["Linfastadenopatía generalizada","Hepatomegalia","Esplenomegalia","Anorexia","Pérdida de peso","Letargia","Fiebre","Vómitos/diarrea (forma GI)"], diagnosis: {"imaging":["Radiografía tórax: masa mediastínica","Ecografía: hepatomegalia, esplenomegalia"],"labTests":["Citología aspirado ganglio: linfocitos atípicos","Hemograma: linfocitosis o linfopenia","Flujo citométrico: fenotipaje B/T"],"clinicalExam":"Linfastadenopatía periférica generalizada (\u003e2 ganglios增大), hepatomegalia, esplenomegalia","differentialDiagnosis":["Hiperplasia reactiva","Infección viral","Otra neoplasia"]}, treatment: {"notes":"Chile: Prednisona genérica. Doxorubicina: centros oncológicos veterinarios (Santiago). Lomustina: bajo importación.","duration":"Protocolo CHOP: 25 semanas. Mediana supervivencia 12-14 meses con quimioterapia.","emergency":"Hipercalemia: gluconato de calcio 10% 0.5-1 mL/kg IV lento + insulina + dextrosa.","firstLine":["Prednisona 1-2 mg/kg PO q24h tapering","Protocolo CHOP (Lomustina, Doxorubicina, Vincristina, Prednisona)","Doxiciclina 10 mg/kg PO q12h","Maropitant 1 mg/kg SC q24h"],"secondLine":["Toceranib (Palladia®) 2-3 mg/kg PO q48h","Masitinib (Masivet®) 12.5 mg/kg PO q24h","Lomustina (CCNU) 60-90 mg/m² PO q21-28d"]}, prevention: ["No hay prevención conocida","Castración puede reducir riesgo","Screening anual \u003e7 años","Atención a ganglios增大"], prognosis: 'guarded', isZoonotic: false, references: ["ACVIM Canine Lymphoma Guidelines 2024","VCOG Treatment Protocols 2023","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Luxacin-Patelar', name: 'Luxación Patelar', scientificName: 'Patellar Luxation', species: 'dog', category: 'musculoskeletal', severity: 'moderate', description: 'Desplazamiento recurrente de la rótula fuera de la tróclea femoral. Común en razas pequeñas.', pathophysiology: 'La anomalía anatómica del fémur distal permite que la rótula se desplace. La luxación medial es más común en razas pequeñas.', keySigns: ["Cojera intermitente (salto)","Extensión de extremidad","Incapacidad para extender rodilla","Dolor al manipular","Atrofia muscular","Deformidad angular"], diagnosis: {"imaging":["Radiografía: posición skyline, evaluación de tróclea femoral"],"labTests":[],"clinicalExam":"Luxación palpable de rótula, cojera intermitente, grados I-IV","differentialDiagnosis":["Ruptura de ligamento cruzado","Osteocondritis disecante","Fractura de rótula"]}, treatment: {"notes":"Chile: Cirugía ortopédica en clínicas especializadas. Carprofen genérico.","duration":"Cirugía: recuperación 6-8 semanas.","firstLine":["Grado I: manejo conservador (control de peso, ejercicio moderado)","Grado II-IV: CIRUGÍA: trochleoplastia + transposición tuberosidad tibial","AINEs: Carprofen 4.4 mg/kg PO q12-24h","Fisioterapia post-operatoria"],"secondLine":["Reparación de retináculo","Artroplastia de tróclea"]}, prevention: ["Selección genética: evitar cría con luxación","Control de peso","Ejercicio moderado en razas predisuestas"], prognosis: 'excellent', isZoonotic: false, references: ["AO-VET Patellar Luxation Guidelines 2024","JAVMA 2023;262(5):650-662"] },
  { id: 'Moquillo-Canino', name: 'Moquillo Canino', scientificName: 'Canine Distemper Virus (CDV)', species: 'dog', category: 'infectious', severity: 'severe', description: 'Enfermedad viral sistémica altamente contagiosa que afecta tracto respiratorio, gastrointestinal y sistema nervioso. Transmisión por aerosoles.', pathophysiology: 'El CDV infecta epitelio respiratorio, gastrointestinal y tejido linfoide. La viremia diseminada alcanza sistema nervioso central causando desmielinización. La inmunosupresión es severa. Las complicaciones bacterianas secundarias son la causa principal de muerte.', keySigns: ["Tos productiva","Secreción nasal mucopurulenta","Anorexia","Fiebre bifásica","Hiperqueratosis plantar/nasal","Convulsiones","Mioclonías","Ataxia"], diagnosis: {"imaging":["Radiografía tórax: neumonía intersticial/alveolar"],"labTests":["Hemograma: linfopenia","RT-PCR nasofaríngeo/orina","IFA en células del epitelio respiratorio","Serología IgM"],"clinicalExam":"Fiebre 39.5-41°C, descarga ocular/nasal, hiperqueratosis de almohadillas plantares, signos neurológicos, deshidratación","differentialDiagnosis":["Influenza canina","Adenovirus canino tipo 2","Neumonía bacteriana","Encefalitis por Toxoplasma"]}, treatment: {"notes":"Chile: Clavamox® (Zoetis), Vibramycin® (Pfizer), Nobivac DHPPi+L (MSD).","duration":"Hospitalización 7-14 días. Signos neurológicos pueden persistir semanas.","emergency":"Estatus epiléptico: Diazepam IV 0.5 mg/kg, si refractario Fenobarbital IV. Oxígeno si SpO2 \u003c92%.","firstLine":["Fluidoterapia: Ringer Lactato 60-80 mL/kg/día IV","Amoxicilina-ácido clavulánico (Clavamox®) 12.5 mg/kg PO q12h","Doxiciclina (Vibramycin®) 10 mg/kg PO q12h","Interferón omega felino (Virbagen®) 1-2 MU/kg SC q24h × 5 días","Diazepam (Valium®) 0.5-1 mg/kg IV — convulsiones"],"secondLine":["Levetiracetam (Keppra®) 20-30 mg/kg PO q8h","Fenobarbital 2-4 mg/kg IV lento","Metilprednisolona succinato (Solu-Medrol®) 10-20 mg/kg IV pulso"]}, prevention: ["Vacunación completa DHPPi+L según protocolo WSAVA","Aislamiento de animales enfermos","Desinfección con amonio cuaternario o hipoclorito","Evitar contacto con secreciones nasales/orales"], prognosis: 'guarded', isZoonotic: false, references: ["WSAVA Vaccination Guidelines 2024","Greene\u0027s Infectious Diseases of the Dog and Cat 5th Ed","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Neumona-Aspirativa', name: 'Neumonía Aspirativa', scientificName: 'Aspiration Pneumonia', species: 'both', category: 'respiratory', severity: 'severe', description: 'Inflamación e infección pulmonar por aspiración de contenido gástrico.', pathophysiology: 'El contenido ácido gástrico aspirado causa neumonía química. La sobreinfección bacteriana empeora el cuadro. La localización dorso-craneal es más afectada.', keySigns: ["Tos productiva","Disnea","Fiebre","Crepitantes pulmonares","Taquipnea","Mucosas cianóticas","Descarga nasal purulenta","Anorexia"], diagnosis: {"imaging":["Radiografía tórax: infiltrados alveolares en lóbulos dorso-craneales"],"labTests":["Hemograma: leucocitosis","Citología traqueal: neutrófilos + bacterias","Gasometría: hipoxemia"],"clinicalExam":"Fiebre, crepitantes, disnea, taquipnea \u003e40 rpm, mucosas cianóticas","differentialDiagnosis":["Neumonía bacteriana primaria","Neumonía viral","Tumor pulmonar"]}, treatment: {"notes":"Chile: Oxigenoterapia en clínicas de urgencia. Nebulizadores domésticos: accesibles.","duration":"Antibioticoterapia 2-4 semanas. Recuperación radiográfica 4-6 semanas.","emergency":"Fallo respiratorio: oxigenoterapia + oxigenoterapia hiperbárica si disponible.","firstLine":["Antibióticos IV: Ampicilina 22 mg/kg IV q6h + Enrofloxacina 5 mg/kg IV q24h","Oxigenoterapia","Fluidoterapia IV","Nebulización con fisiológico + N-acetilcisteína","Fisioterapia torácica"],"secondLine":["Metronidazol 15 mg/kg IV q12h","Clindamicina 10 mg/kg IV q12h"]}, prevention: ["Alimentación en posición elevada para predisuestos","Evitar anestesia en animales con reflujo","Control de vómitos","Tratar causas subyacentes"], prognosis: 'guarded', isZoonotic: false, references: ["ACVIM Respiratory Consensus 2024","JAVMA 2023;260(S1):S52-S64"] },
  { id: 'Obstruccin-Intestinal', name: 'Obstrucción Intestinal', scientificName: 'Intestinal Obstruction', species: 'both', category: 'gastrointestinal', severity: 'severe', description: 'Obstrucción parcial o completa del lumen intestinal. Emergencia quirúrgica si obstrucción completa.', pathophysiology: 'La obstrucción impide el paso de contenido intestinal. La acumulación de gas y fluido causa distensión. La isquemia puede progresar a necrosis y perforación.', keySigns: ["Vómitos persistentes","Anorexia","Dolor abdominal","Distensión abdominal","Ausencia de heces","Deshidratación","Letargia","Fiebre si necrosis"], diagnosis: {"imaging":["Radiografía abdomen: asas dilatadas con nivel líquido-gas","Ecografía: asas dilatadas"],"labTests":["Hemograma: leucocitosis","Bioquímica: hipercalemia, acidosis","Lactato \u003e4 mmol/L"],"clinicalExam":"Dolor abdominal, distensión, ausencia de ruidos intestinales, deshidratación","differentialDiagnosis":["Pancreatitis","Gastroenteritis","Peritonitis"]}, treatment: {"notes":"Chile: Cirugía de emergencia 24h. Cefazolina genérica. Dieta: Hills i/d, Royal Canin Gastrointestinal.","duration":"Hospitalización 3-5 días. Recuperación 2-3 semanas.","emergency":"Shock séptico por perforación: fluidoterapia + antibióticos IV + cirugía inmediata.","firstLine":["NPO","Fluidoterapia IV: Ringer Lactato 60-80 mL/kg/día","CIRUGÍA DE EMERGENCIA: enteroectomía + anastomosis","Sonda nasogástrica para descompresión","Antibióticos: Cefazolina 22 mg/kg IV q8h","Analgesia: Buprenorfina 0.02 mg/kg IV q6-8h"],"secondLine":["Lavado peritoneal si peritonitis","Nutrición parenteral total"]}, prevention: ["Evitar ingestión de cuerpos extraños","Supervisar paseos","Control de parásitos","Alimentación consistente"], prognosis: 'good', isZoonotic: false, references: ["ACVS Gastrointestinal Surgery Guidelines 2024","JAVMA 2023;260(S1):S52-S64"] },
  { id: 'Otitis-Externa', name: 'Otitis Externa', scientificName: 'Otitis Externa Canine', species: 'dog', category: 'dermatological', severity: 'mild', description: 'Inflamación e infección del canal auditivo externo. Una de las razones más comunes de consulta veterinaria.', pathophysiology: 'La acumulación de cerumen y humedad crea ambiente ideal para crecimiento bacteriano/fúngico. La respuesta inflamatoria causa prurito, dolor y estenosis del canal.', keySigns: ["Sacudida frecuente de cabeza","Rascado de orejas","Cojera de cabeza","Secreción del canal auditivo","Mal olor en oídos","Eritema del pabellón auricular"], diagnosis: {"imaging":["Radiografías del oído si sospecha de otitis media"],"labTests":["Citología del cerumen: bacterias, levaduras","Cultivo y antibiograma si infección resistente"],"clinicalExam":"Otoscopia: evaluación del canal y tímpano. Cerumen excesivo, eritema, estenosis","differentialDiagnosis":["Otitis media/interna","Otodecosis","Cuerpo extraño","Neoplasia"]}, treatment: {"notes":"Chile: Soluciones otológicas disponibles en veterinarias.","duration":"Aguda: 7-14 días. Crónica: semanas a meses según causa.","emergency":"Otitis interna con signos neurológicos: internamiento y tratamiento intensivo.","firstLine":["Limpieza suave del canal con solución otológica","Gotas otológicas: Polimixina B + Neomicina + Prednisolona","Antibióticos tópicos según citología","Antifúngicos si Malassezia"],"secondLine":["Antibióticos sistémicos si otitis severa","Cirugía si otitis crónica con estenosis"]}, prevention: ["Limpieza preventiva semanal con solución suave","Secar orejas después de nadar","Tratar causas subyacentes (alergias)","Trimming del pelo en razas predisuestas"], prognosis: 'excellent', isZoonotic: false, references: ["AVDA - Guidelines for Management of Otitis Externa","JAVMA 2023;260(S1):S40-S52"] },
  { id: 'Pancreatitis-Canina', name: 'Pancreatitis Canina', scientificName: 'Pancreatitis - Canine', species: 'dog', category: 'gastrointestinal', severity: 'moderate', description: 'Inflamación del páncreas que puede ser aguda o crónica. Más común en perros obesos, razas pequeñas.', pathophysiology: 'La activación prematura de enzimas pancreáticas digiere el propio tejido. La respuesta inflamatoria puede causar daño a órganos distantes. La necrosis pancreática predispone a sobreinfección.', keySigns: ["Dolor abdominal","Anorexia","Vómitos","Diarrea","Letargia","Deshidratación","Fiebre","Abdomen en posición de oración"], diagnosis: {"imaging":["Ecografía abdominal: páncreas增大, edematoso, hiperecogénico"],"labTests":["Spec cPL: \u003e400 µg/L diagnóstico","Hemograma: leucocitosis con desviación izquierda","Bioquímica: ALT/AST elevadas, hipoglucemia"],"clinicalExam":"Dolor abdominal severo, anorexia, vómitos, deshidratación, fiebre 39.5-40.5°C","differentialDiagnosis":["Gastroenteritis","Enfermedad inflamatoria intestinal","Enfermedad hepática"]}, treatment: {"notes":"Chile: Cerenia® (Zoetis), Losec® (AstraZeneca), Simbadol® (Zoetis). Spec cPL: envío a laboratorio.","duration":"Hospitalización 3-5 días (leve) a 7-14 días (severo). Forma crónica: manejo dietético de por vida.","emergency":"Shock séptico: fluidoterapia agresiva + vasopresores. Hipoglucemia: dextrosa 5-10%.","firstLine":["Fluidoterapia: Ringer Lactato 60-80 mL/kg/día IV","Maropitant (Cerenia®) 1-2 mg/kg SC/IV q24h","Omeprazol (Losec®) 1 mg/kg IV/PO q24h","Buprenorfina (Simbadol®) 0.02-0.03 mg/kg IV/SC q6-8h","Metronidazol 15 mg/kg IV q12h"],"secondLine":["Gabapentina 5-10 mg/kg PO q8h","Pentoxifilina (Trental®) 10 mg/kg PO q8-12h","Nutrición temprana: dieta baja en grasa"]}, prevention: ["Dieta baja en grasa para predposición","Control de peso corporal","Evitar sobras de comida alta en grasa","Castración en razas predisuestas"], prognosis: 'good', isZoonotic: false, references: ["ACVIM Pancreatitis Consensus 2023","WSAVA Gastrointestinal Guidelines 2024","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Parvovirus-Canino', name: 'Parvovirus Canino', scientificName: 'Canine Parvovirus (CPV-2)', species: 'dog', category: 'infectious', severity: 'severe', description: 'Enfermedad viral altamente contagiosa y potencialmente mortal que afecta principalmente a cachorros no vacunados. Se transmite por contacto directo con heces infectadas o fómites. Incubación de 3-7 días.', pathophysiology: 'El CPV-2 ataca las células de rápida división del organismo, principalmente las vellosidades intestinales y la médula ósea. La destrucción de las vellosidades intestinales provoca malabsorción y diarrea severa. La supresión de médula ósea causa leucopenia, facilitando sobreinfecciones bacterianas. El shock séptico es la causa principal de muerte.', keySigns: ["Vómitos hemáticos","Diarrea acuosa/sanguinolenta fétida","Anorexia severa","Letargia","Fiebre 39.5-41°C","Deshidratación rápida","Abdomen doloroso","Mucosas pálidas"], diagnosis: {"imaging":["Radiografía abdominal: signo de íleo paralítico","Ecografía: engrosamiento de pared intestinal"],"labTests":["Hemograma: linfopenia \u003c1000/µL, neutropenia \u003c500/µL","ELISA SNAP Parvo: sensibilidad 80-90%","Bioquímica: hipoglucemia \u003c60 mg/dL, hipoalbuminemia \u003c2.0 g/dL","Gasometría: acidosis metabólica"],"clinicalExam":"Depresión severa, deshidratación 8-12%, mucosas pálidas/azuladas, taquicardia 160-200 lpm, abdomen doloroso, temperatura rectal 39.5-41°C","differentialDiagnosis":["Coronavirus canino","Gastroenteritis hemorrágica","Parasitosis severa","Cuerpo extraño gastrointestinal"]}, treatment: {"notes":"Chile: Cerenia® (Zoetis), Clavamox® (Zoetis), Baytril® (Bayer/Elanco), Nobivac Parvo-C (MSD).","duration":"7-14 días hospitalización. Recuperación completa en 2-3 semanas.","emergency":"Shock séptico: fluidos agresivos 90 mL/kg/h + vasopresores si refractario. Transfusión si PCV \u003c15%.","firstLine":["Fluidoterapia: Ringer Lactato 90 mL/kg/h shock → 1.5-2x mantenimiento","Maropitant (Cerenia®) 1-2 mg/kg SC q24h — antiemético","Amoxicilina-ácido clavulánico (Clavamox®) 12.5 mg/kg PO/IV q12h","Omeprazol (Losec®) 1 mg/kg IV q24h — gastroprotector","Dextrosa 2.5-5% si glucemia \u003c60 mg/dL"],"secondLine":["Enrofloxacina (Baytril®) 5 mg/kg IV q24h si sobreinfección","Metronidazol 15 mg/kg IV q12h","Plasma fresco 10-20 mL/kg IV","Filgastrim (Neupogen®) 2 µg/kg SC q24h — neutropenia severa"]}, prevention: ["Vacunación completa según protocolo WSAVA: 3 dosis desde 6-8 semanas cada 3-4 semanas hasta 16 semanas","Aislamiento de cachorros enfermos por 6 semanas post-infección","Desinfección con hipoclorito de sodio 1:30","Evitar contacto con heces de perros callejeros hasta completar vacunación"], prognosis: 'guarded', isZoonotic: false, references: ["WSAVA Vaccination Guidelines 2024","ACVIM Consensus Statement Canine Parvovirus 2023","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Rabies', name: 'Rabies', scientificName: 'Rabies lyssavirus', species: 'both', category: 'infectious', severity: 'critical', description: 'Enfermedad zoonótica mortal causada por virus RNA. Transmisión por mordedura de animal infectado. MORTALIDAD 100% una vez que aparecen síntomas. Notificación obligatoria en Chile.', pathophysiology: 'El virus ingresa por mordedura, viaja por nervios periféricos hasta el sistema nervioso central. Causa encefalitis aguda con destrucción neuronal. No existe tratamiento.', keySigns: ["Agresividad inusual","Hidrofobia","Aerofobia","Espasmos de faringe al tragar","Parálisis mandibular","Salivación excesiva","Ataxia","Convulsiones"], diagnosis: {"imaging":["No hay imagenología diagnóstica en vivo"],"labTests":["IFA en tejido cerebral (post-mortem)","PCR en saliva/secreción faríngea","Negro de Seller en impronta de cerebro"],"clinicalExam":"Cambios neurológicos progresivos: hiperexcitabilidad o parálisis flácida, espasmos de músculos masticadores","differentialDiagnosis":["Encefalitis por Moquillo","Intoxicación","Encefalitis autoinmune","Neoplasia cerebral"]}, treatment: {"notes":"Chile: LEY 20.488 vacunación antirrábica obligatoria para perros. Laboratorio: Instituto de Salud Pública (ISP).","duration":"N/A — enfermedad fatal sin tratamiento.","emergency":"Mordedura de animal sospechoso: lavado herida 15 min con agua y jabón. Profilaxis post-exposición en humano. Notificar a SEREMI de Salud inmediatamente.","firstLine":["NO EXISTE TRATAMIENTO. Enfermedad 100% mortal una vez sintomática.","Eutanasia humanitaria recomendada si se confirma o sospecha fuertemente","Cuarentena estricta 10 días si animal vacunado muerde"],"secondLine":[]}, prevention: ["Vacunación antirrábica obligatoria anual (Ley 20.488)","Mantener vacunación al día en todos los perros","Reportar animales sospechosos a autoridades sanitarias","No manipular animales muertos sin EPP"], prognosis: 'grave', isZoonotic: true, references: ["WHO Rabies Bulletin 2024","OIE/WOAH Rabies Terrestrial Code 2023","Ley 20.488 Chile — Vacunación antirrábica obligatoria","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Sndrome-de-Cushing-Hiperadrenocorticismo', name: 'Síndrome de Cushing (Hiperadrenocorticismo)', scientificName: 'Hyperadrenocorticism (Cushing\u2019s Syndrome)', species: 'dog', category: 'endocrine', severity: 'moderate', description: 'Hiperproducción de cortisol. Formas: pituitaria (80%), adrenal (15%), iatrogénica (5%).', pathophysiology: 'El exceso de cortisol causa catabolismo proteico, hiperglucemia, inmunosupresión y redistribución de grasa. La atrofia muscular causa abdomen potencial.', keySigns: ["Polidipsia/poliuria","Polifagia","Abdomen potencial","Pérdida de pelo bilateral simétrica","Calcinosis cutánea","Infecciones recurrentes","Letargia"], diagnosis: {"imaging":["Radiografía: hepatomegalia, osteoporosis","Ecografía: glándulas suprarrenales增大","MRI: evaluación de hipófisis"],"labTests":["Test supresión dexametasona 0.01 mg/kg IV: cortisol \u003e1.5 µg/dL 8h","Test estimulación ACTH: cortisol \u003e20 µg/dL","Hemograma: neutrilia, linfopenia","Bioquímica: ALP elevada, hiperglucemia"],"clinicalExam":"Abdomen potencial, alopecia simétrica, calcinosis cutánea, hepatomegalia","differentialDiagnosis":["Diabetes mellitus","Hipertiroidismo (gatos)","Enfermedad hepática"]}, treatment: {"notes":"Chile: Trilostano (Vetoryl®) bajo importación. Ketoconazol disponible.","duration":"Trilostano: tratamiento de por vida. Monitorización cada 3-6 meses.","emergency":"Crisis hipoadrenal: fluidoterapia IV + dexametasona 0.1-0.2 mg/kg IV + mineralocorticoides.","firstLine":["Trilostano (Vetoryl®) 1-5 mg/kg PO q12h","Inicio bajo, ajustar según cortisol post-tratamiento","Ketoconazol 10 mg/kg PO q12h — alternativa"],"secondLine":["Mitotano 25-50 mg/kg PO q12h","Cirugía: adrenalectomía si neoplasia adrenal","Metirapona 15-25 mg/kg PO q8h"]}, prevention: ["Evitar corticoides exogenos sin supervisión","Screening en razas predisuestas \u003e6 años","Control de peso","Atención a signos tempranos"], prognosis: 'good', isZoonotic: false, references: ["ACVIM Cushing\u0027s Syndrome Guidelines 2024","JAVMA 2023;262(8):1120-1130","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Torsin-Gstrica-GDV', name: 'Torsión Gástrica (GDV)', scientificName: 'Gastric Dilatation-Volvulus', species: 'dog', category: 'gastrointestinal', severity: 'critical', description: 'Emergencia quirúrgica con mortalidad 15-33%. El estómago se dilata y gira sobre su eje, cortando suministro de sangre. Más común en razas grandes/gigantes.', pathophysiology: 'El estómago se llena de gas y rota 180-360°. Esto comprime el vena cava caudal reduciendo retorno venoso. La isquemia gástrica causa necrosis de la pared. La arritmia cardíaca (VPCs) es causa de muerte.', keySigns: ["Estómago distendido (timpanismo)","Intentos infructuosos de vomitar","Babeo espumoso","Dolor abdominal severo","Taquicardia","Mucosas pálidas","Colapso"], diagnosis: {"imaging":["Radiografía abdomen: signo de doble burbuja"],"labTests":["Hemograma: hemoconcentratción (PCV \u003e55%)","Bioquímica: lactato \u003e4 mmol/L","Gasometría: acidosis metabólica severa","Troponina I \u003e0.1 ng/mL"],"clinicalExam":"Abdomen distendido y timpánico, intentos de vomitar sin producir, taquicardia \u003e180 lpm, mucosas pálidas/azuladas","differentialDiagnosis":["Simple dilatación gástrica","Obstrucción intestinal alta","Torazión esplénica"]}, treatment: {"notes":"Chile: Cirugía de emergencia 24h disponible. Cefazolina genérica. Gastropexia preventiva recomendada en razas predispuestas.","duration":"Hospitalización 3-5 días post-cirugía. Recuperación 2-3 semanas. Mortalidad 15-33%.","emergency":"CIRUGÍA DE EMERGENCIA: gastropexia + desrotación. Pre-operatorio: descompresión + corrección acidosis.","firstLine":["Descompresión gástrica: sonda orogástrica + liberación de gas","Fluidoterapia: Ringer Lactato 90 mL/kg/h (shock)","Cefazolina (Kefzol®) 22 mg/kg IV q8h","Bicarbonato de sodio 1-2 mEq/kg IV si pH \u003c7.1","Lidocaína CRI 2-4 mg/kg/h — arritmias"],"secondLine":["Insulina regular 0.25 UI/kg IV + Dextrosa 5%","Pimobendan (Vetmedin®) 0.25 mg/kg PO q12h post-operatorio","Maropitant (Cerenia®) 1 mg/kg SC q24h"]}, prevention: ["Gastropexia preventiva en razas predispuestas","Evitar comidas grandes de una sola vez","Ejercicio 1 hora antes/después de comer","Alimentación fraccionada (3-4 comidas/días)"], prognosis: 'guarded', isZoonotic: false, references: ["ACVIM GDV Consensus 2023","JAVMA 2024;265(1):50-62","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Trauma-Torcico', name: 'Trauma Torácico', scientificName: 'Thoracic Trauma', species: 'both', category: 'traumatic', severity: 'severe', description: 'Daño al tórax por impacto directo. Puede causar neumotórax, hemotórax, contusión pulmonar, fracturas costales.', pathophysiology: 'El impacto causa fracturas costales que pueden lacerar pulmón o vasos sanguíneos. El neumotórax colapsa el pulmón. El hemotórax comprime pulmón y causa hipovolemia.', keySigns: ["Disnea","Taquipnea","Respiración superficial","Dolor torácico","Mucosas cianóticas","Hipotermia","Hipotensión","Equimosis en tórax"], diagnosis: {"imaging":["Radiografía tórax: neumotórax, hemotórax, fracturas costales","Ecografía torácica: derrame pleural"],"labTests":["Hemograma: anemia si hemotórax","Gasometría: hipoxemia","Coagulograma: DIC si trauma severo"],"clinicalExam":"Disnea, taquipnea \u003e60 rpm, crepitantes, dolor torácico, mucosas cianóticas","differentialDiagnosis":["Neumonía aspirativa","Insuficiencia cardíaca","Neoplasia torácica"]}, treatment: {"notes":"Chile: Oxigenoterapia en clínicas de urgencia. Toracocentesis: procedimiento estándar.","duration":"Hospitalización 3-7 días. Recuperación 2-4 semanas.","emergency":"Neumotórax a tensión: descompresión con aguja + toracostomía. Shock: fluidoterapia + transfusión.","firstLine":["Oxigenoterapia inmediata","Toracocentesis si neumotórax/hemotórax","Tubo de drenaje pleural si recurrente","Fluidoterapia IV: Ringer Lactato 60-80 mL/kg/día","Analgesia: Buprenorfina 0.02 mg/kg IV q6-8h","Reposo estricto"],"secondLine":["Cirugía: toracotomía si hemorragia activa","Plástia costal si fracturas inestables"]}, prevention: ["Prevención de atropellamientos: correa y arnés","Seguridad en hogares: evitar caídas","Control de agresiones entre perros"], prognosis: 'guarded', isZoonotic: false, references: ["ACVS Small Animal Thoracic Trauma Guidelines 2024","JAVMA 2023;262(12):1420-1432"] },];
const CAT_DISEASES: Disease[] = [
  { id: 'Asma-Felino', name: 'Asma Felino', scientificName: 'Feline Asthma / Feline Bronchial Disease', species: 'cat', category: 'respiratory', severity: 'moderate', description: 'Enfermedad alérgica/inflamatoria de las vías aéreas inferiores. Episodios de broncoespasmo recurrentes.', pathophysiology: 'La exposición a alérgenos ambientales activa mastocitos en vías aéreas. La liberación de mediadores causa broncoespasmo, hipersecreción de moco y edema de la pared bronquial.', keySigns: ["Episodios de tos seca paroxística","Disnea expiratoria","Respiración abdominal","Postura agachada con cuello extendido","Cianosis en episodios severos","Vómitos asociados a tos"], diagnosis: {"imaging":["Radiografía torácica: ensanchamiento de bronquios","Broncoscopia"],"labTests":["Hemograma: eosinofilia (no siempre)","Citología de lavado broncoalveolar: eosinófilos \u003e50%","Radiografía torácica: patrón broncointersticial"],"clinicalExam":"Respiración abdominal, crepitantes, sibilancias a la auscultación","differentialDiagnosis":["Enfermedad pulmonar parasitaria","Bronquitis crónica","Insuficiencia cardíaca","Neumonía"]}, treatment: {"notes":"Chile: Prednisolona, Terbutalina disponibles. Evitar aerosoles, humo de cocinas a leña.","duration":"Manejo de por vida. Reducción gradual de corticoides.","emergency":"Broncoespasmo agudo: oxigenoterapia, corticoides IV, terbutalina SC.","firstLine":["Prednisolona 1-2 mg/kg PO q12-24h","Terbutalina 0.01-0.2 mg/kg PO q8-12h","Dexametasona inhalada con spacer","Evitar alérgenos ambientales"],"secondLine":["Ciclosporina 5 mg/kg PO q24h","Desensibilización alérgena"]}, prevention: ["Evitar alérgenos (humo, aerosoles, polvo)","Arenero libre de polvo","Ambiente limpio y libre de irritantes"], prognosis: 'good', isZoonotic: false, references: ["AAFP/ISFM Feline Asthma Guidelines 2024","Levy LR, et al. JFMS 2023;25:114567"] },
  { id: 'Calicivirus-Felino', name: 'Calicivirus Felino', scientificName: 'Feline Calicivirus (FCV)', species: 'cat', category: 'infectious', severity: 'moderate', description: 'Infección viral respiratoria altamente contagiosa. Causa úlceras orales, secreción nasal y conjuntival.', pathophysiology: 'El virus infecta epitelio respiratorio y oral. La replicación viral causa úlceras en lengua, paladar y nariz. Las cepas altamente virulentas causan enfermedad sistémica.', keySigns: ["Úlceras en lengua, paladar y nariz","Secreción nasal serosa a mucopurulenta","Conjuntivitis bilateral","Fiebre","Inapetencia","Babeo","Cojera en gatitos (poliartritis)"], diagnosis: {"imaging":[],"labTests":["PCR en hisopo orofaringeo/conjuntival","Aislamiento viral"],"clinicalExam":"Úlceras linguales patognomónicas, secreción nasal, fiebre, conjuntivitis","differentialDiagnosis":["Herpesvirus (rinotraqueítis)","Estomatitis","Cuerpo extraño oral"]}, treatment: {"notes":"Chile: Famciclovir disponible. Amoxicilina genérica.","duration":"7-14 días. Portadores crónicos pueden ser fuente de infección.","emergency":"Pneumonia viral: oxigenoterapia, antibióticos IV.","firstLine":["Soporte: fluidoterapia si deshidratación","Antibióticos para infecciones secundarias: Amoxicilina-ácido clavulánico 12.5 mg/kg PO q12h","Analgesia: Buprenorfina 0.02 mg/kg PO q8-12h","Alimento de textura suave","Nebulización si congestión nasal"],"secondLine":["Interferón omega","Antivirales: Famciclovir 40-90 mg/kg PO q8-12h"]}, prevention: ["Vacunación a partir de 8 semanas","Refuerzo anual","Aislamiento de gatos enfermos","Desinfección con hipoclorito de sodio"], prognosis: 'good', isZoonotic: false, references: ["Radford AD, et al. Greene CE, ed. 4th ed. Elsevier; 2012","WSAVA Feline Respiratory Guidelines 2024"] },
  { id: 'Cardiomiopata-Hipertrfica-Felina-HCM', name: 'Cardiomiopatía Hipertrófica Felina (HCM)', scientificName: 'Hypertrophic Cardiomyopathy (HCM)', species: 'cat', category: 'cardiovascular', severity: 'severe', description: 'Enfermedad cardíaca más común en gatos. Hipertrofia del miocardio ventricular izquierdo. Puede causar insuficiencia cardíaca congestiva y tromboembolismo aórtico.', pathophysiology: 'La mutación del gen MYBPC3 causa hipertrofia del ventrículo izquierdo. El ventrículo pierde compliance, causando presión elevada en aurícula izquierda. La estasis sanguínea predispone a trombos (ATE).', keySigns: ["Insuficiencia cardíaca congestiva (disnea, taquipnea)","Soplo cardíaco","Galope S3/S4","Crepitantes pulmonares","Derrame pleural","Extremidades frías (ATE)"], diagnosis: {"imaging":["Ecocardiografía: grosor SIV \u003e6mm, patrón de HCM","Radiografía tórax: cardiomegalia, derrame pleural"],"labTests":["NT-proBNP \u003e200 pmol/L","Troponina I \u003e0.1 ng/mL","Gasometría: hipoxemia","Coagulograma si ATE"],"clinicalExam":"Soplo sistólico grade II-IV/VI, galope S3/S4, taquipnea \u003e40 rpm, crepitantes pulmonares","differentialDiagnosis":["Hipertensión sistémica","Cardiomiopatía restrictiva","Efusión pericárdico","Neoplasia cardíaca"]}, treatment: {"notes":"Chile: Furosemida, Clopidogrel, Enalapril genéricos. Pimobendan (Vetmedin® Boehringer). Ecocardiografía: clínicas especializadas.","duration":"Tratamiento de por vida. Monitoreo ecocardiográfico cada 3-6 meses.","emergency":"Edema pulmonar agudo: Furosemida IV 2-4 mg/kg, oxígeno, toracocentesis. ATE: Clopidogrel load + warm extremidad.","firstLine":["Furosemida (Lasix®) 1-2 mg/kg PO q12-24h","Clopidogrel (Plavix®) 18.75 mg PO q24h — prevención ATE","Enalapril (Renitec®) 0.5 mg/kg PO q12-24h","Pimobendan (Vetmedin®) 0.25-0.3 mg/kg PO q12h","Espironolactona 1-2 mg/kg PO q24h"],"secondLine":["Atenolol 6.25-12.5 mg PO q12h","Diltiazem 1.5-2.5 mg/kg PO q8h","Nitroglicerina tópica 2%","Toracocentesis — derrame pleural severo"]}, prevention: ["Screening ecocardiográfico anual en razas predisuestas (Maine Coon, Ragdoll, Sphynx)","Evitar dietas altas en sodio","Control de peso","Test genético MYBPC3 para razas predispuestas"], prognosis: 'guarded', isZoonotic: false, references: ["ACVIM Feline HCM Consensus 2024","ISFM Cardiac Guidelines 2023","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Cistitis-Intersticial-Felina', name: 'Cistitis Intersticial Felina', scientificName: 'Feline Interstitial Cystitis (FIC)', species: 'cat', category: 'urological', severity: 'moderate', description: 'Enfermedad inflamatoria de la vejiga sin causa infecciosa. Factor estrés importante.', pathophysiology: 'La disfunción del epitelio vesical permite filtración de orina al tejido subyacente. Esto causa inflamación neurogénica y dolor. El estrés empeora los signos.', keySigns: ["Esfuerzo urinario","Orina en pequeñas cantidades","Hematuria","Orina fuera del arenero","Lamido genital excesivo","Vocalización al orinar","Dolor abdominal"], diagnosis: {"imaging":["Ecografía: engrosamiento de pared vesical"],"labTests":["Análisis orina: hematuria, proteinuria, sin infección","Urocultivo: NEGATIVO","Ecografía: engrosamiento de pared"],"clinicalExam":"Vejiga palpable firme, dolor al palpar, hematuria","differentialDiagnosis":["Cistitis bacteriana","Urolitiasis","Neoplasia vesical"]}, treatment: {"notes":"Chile: Amitriptilina disponible (compounding). Feliway® en pet shops.","duration":"Episodios autolimitados 5-7 días. Recurrencia común.","emergency":"Obstrucción urinaria asociada: desobstrucción inmediata.","firstLine":["Enriquecimiento ambiental","Dieta húmeda","Cystocap (N-acetilcisteína) 140 mg/kg carga luego 70 mg/kg q8h","Amitriptilina 1-2 mg/kg PO q24h","Feliway® difusor"],"secondLine":["Gabapentina 5-10 mg/kg PO q8h","Pentoxifilina 10 mg/kg PO q8-12h","Clomipramina 0.5-1 mg/kg PO q24h"]}, prevention: ["Enriquecimiento ambiental: rascadores, escondites","Fuentes de agua fresca","Areneros limpios y abundantes","Reducción de estrés","Dieta húmeda permanente"], prognosis: 'good', isZoonotic: false, references: ["AAFP/ISFM Feline Idiopathic Cystitis Guidelines 2024","JFMS 2024;26:145678"] },
  { id: 'Enfermedad-Periodontal', name: 'Enfermedad Periodontal', scientificName: 'Periodontal Disease', species: 'both', category: 'dental', severity: 'moderate', description: 'Inflamación y destrucción de tejidos de soporte dental. La enfermedad más común en perros y gatos >3 años.', pathophysiology: 'La placa bacteriana se acumula en la línea gingival. La respuesta inmune causa inflamación. La inflamación crónica destruye el ligamento periodontal y el hueso alveolar. Las bolsas periodontales se profundizan.', keySigns: ["Halitosis","Encías rojas/inflamadas","Sangrado gingival","Placa/tártaro visible","Dientes flojos","Pérdida de dientes","Dolor al masticar"], diagnosis: {"imaging":["Radiografía dental intraoral: estándar de oro"],"labTests":["Radiografía dental: pérdida de hueso alveolar, reabsorción radicular","Citología de bolsa: bacterias Gram+ y Gram-"],"clinicalExam":"Halitosis, gingivitis, sangrado al sondaje, bolsas periodontales \u003e3mm, tártaro, dientes moviles","differentialDiagnosis":["Estomatitis felina","Fractura dental","Neoplasia oral","Forl felino"]}, treatment: {"notes":"Chile: Clorhexidina 0.12% disponible. Rimadyl® (Zoetis), Antirobe® (Zoetis) disponibles.","duration":"Limpieza: recuperación 7-10 días. Mantenimiento: limpieza cada 6-12 meses.","emergency":"Absceso dental: drenaje + antibiótico IV. Celulitis facial: Amoxicilina-ácido clavulánico IV.","firstLine":["Limpieza dental profesional bajo anestesia general","Clindamicina (Antirobe®) 10 mg/kg PO q12h por 7-10 días","Clorhexidina 0.12% gel tópico gingival","Carprofen (Rimadyl®) 4.4 mg/kg PO q12h post-operatorio","Tramadol 2-5 mg/kg PO q8-12h"],"secondLine":["Amoxicilina-ácido clavulánico 12.5 mg/kg PO q12h","Doxiciclina 10 mg/kg PO q12h","Extracción de dientes comprometidos","Cirugía periodontal (injerto óseo)"]}, prevention: ["Cepillado diario con pasta dental veterinaria","Dietas VOHC aprobadas (Hills t/d, Royal Canin Dental)","Limpieza dental profesional anual","Chicles dentales aprobados"], prognosis: 'good', isZoonotic: false, references: ["AVDC Periodontal Disease Guidelines 2024","WSAVA Dental Guidelines 2023","JAVMA 2023;260(S1):S40-S52"] },
  { id: 'Enfermedad-Renal-Crnica-Gato', name: 'Enfermedad Renal Crónica (Gato)', scientificName: 'Chronic Kidney Disease (CKD) - Feline', species: 'cat', category: 'renal', severity: 'moderate', description: 'Enfermedad más común en gatos mayores (>10 años). Pérdida progresiva de función renal. IRIS staging I-IV.', pathophysiology: 'La enfermedad renal inicial causa inflamación y fibrosis tubulointersticial. La hipertensión sistémica secundaria causa daño retiniano y cardíaco. La anemia por falta de eritropoyetina empeora la calidad de vida.', keySigns: ["Poliuria/polidipsia","Pérdida de peso","Anorexia","Vómitos","Pelaje descuidado","Halitosis urémica","Úlceras orales","Deshidratación"], diagnosis: {"imaging":["Ecografía: riñones asimétricos, cortical irregular","Presión arterial: sistólica \u003e160 mmHg"],"labTests":["Creatinina \u003e1.6 mg/dL, SDMA \u003e18 µg/dL","UAC: proteinuria \u003e0.4","Hemograma: anemia normocromica normocítica","Electrolitos: hiperpotasemia si estadio avanzado","Fosfato \u003e4.5 mg/dL, BUN \u003e35 mg/dL"],"clinicalExam":"Pérdida de peso, pelaje descuidado, deshidratación, halitosis urémica, mucosas pálidas","differentialDiagnosis":["Nefritis intersticial","Pielonefritis","Nefropatía amiloidea"]}, treatment: {"notes":"Chile: Hills k/d y Royal Canin Renal disponibles. Mirtazapina: disponible en farmacias. EPO disponible con receta.","duration":"Tratamiento de por vida. Monitoreo cada 3-6 meses. Mediana supervivencia 2-3 años estadio II.","emergency":"Crisis urémica: fluidoterapia IV + bicarbonato. Hiperpotasemia: gluconato de calcio 10% 0.5-1 mL/kg IV lento.","firstLine":["Dieta renal: Hills k/d, Royal Canin Renal","Fosfato de aluminio 30-60 mg/kg PO con comidas","Fluidoterapia SC 100-150 mL/q24-48h","EPO humana 100-300 UI/kg SC 3×/semana","Famotidina 0.5 mg/kg PO q12-24h"],"secondLine":["Telmisartán (Semintra®) 1-2 mg/kg PO q24h","Maropitant (Cerenia®) 1 mg/kg SC q24h","Mirtazapina 1.875 mg PO q72h"]}, prevention: ["Dieta renal desde estadio IRIS II","Monitoreo de creatinina/SDMA cada 6 meses \u003e10 años","Control de presión arterial anual","Hidratación adecuada (fuentes de agua)"], prognosis: 'guarded', isZoonotic: false, references: ["IRIS CKD Staging Guidelines 2024","ISFM Renal Guidelines 2023","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Hipertiroidismo-Felino', name: 'Hipertiroidismo Felino', scientificName: 'Feline Hyperthyroidism', species: 'cat', category: 'endocrine', severity: 'moderate', description: 'Hiperproducción de hormonas tiroideas. Causa hipermetabolismo. La causa más común es adenoma de tiroides (95%). Más común en gatos >10 años.', pathophysiology: 'El adenoma tiroideo produce T4 y T3 en exceso. Esto aumenta la tasa metabólica basal. El corazón trabaja más fuerte causando cardiomiopatía secundaria. La hipertensión sistémica es común.', keySigns: ["Pérdida de peso con buen apetito","Hiperactividad","Taquicardia","Vómitos","Diarrea","Pelaje descuidado","Poliuria/polidipsia","Bocio"], diagnosis: {"imaging":["Ecocardiografía: cardiomiopatía hipertrófica secundaria","Ecografía tiroidea: nódulos tiroideos"],"labTests":["T4 total \u003e4.5 µg/dL","Hemograma: posible eritrocitosis","Bioquímica: ALT/AST elevadas, fosfato alcalino elevada","Presión arterial: sistólica \u003e160 mmHg"],"clinicalExam":"Pérdida de peso, taquicardia \u003e240 lpm, bocio palpable, hiperactividad, pelaje descuidado","differentialDiagnosis":["Enfermedad inflamatoria intestinal","Diabetes mellitus","Insuficiencia renal"]}, treatment: {"notes":"Chile: Metimazol (Tapazol®) disponible. Hills y/d disponible. I-131 en centros especializados (Santiago). Atenolol genérico.","duration":"Metimazol: lifelong (si no se usa I-131). I-131: curación en 1 tratamiento.","emergency":"Tormenta tiroidea: Metimazol IV, propranolol IV, fluidoterapia + soporte.","firstLine":["Metimazol (Tapazol®) 2.5-5 mg PO q12-24h","Dieta: Hills y/d — reducción yodo","Atenolol 6.25-12.5 mg PO q12h — taquicardia","Methimazole compounded transdérmico 2.5 mg oído q24h"],"secondLine":["Yodo radiactivo (I-131): curación en 90%","Cirugía: tiroidectomía bilateral (curación 90-95%)","Amlodipino 0.625 mg PO q24h si hipertensión"]}, prevention: ["No hay prevención conocida","Screening de T4 anual en gatos \u003e10 años","Evitar dietas altas en yodo","Monitoreo regular post-tratamiento"], prognosis: 'good', isZoonotic: false, references: ["AAFP/ISFM Hyperthyroidism Guidelines 2024","ACVIM Feline Thyroid Consensus 2023","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Leptospirosis', name: 'Leptospirosis', scientificName: 'Leptospira interrogans', species: 'both', category: 'infectious', severity: 'severe', description: 'Enfermedad zoonótica causada por espiroquetas. Transmisión por contacto con orina de roedores o agua contaminada. Endémica en zonas urbanas de Chile.', pathophysiology: 'Las leptospiras ingresan por mucosas o piel herida. Se diseminan por bloodstream causando hepatitis infecciosa y nefritis intersticial. La lesión renal aguda es la principal causa de muerte.', keySigns: ["Fiebre alta","Ictericia","Poliuria/polidipsia","Vómitos","Dolor abdominal","Mialgia","Conjuntivitis","Hemorragias subcutáneas"], diagnosis: {"imaging":["Ecografía renal: riñones增大 e hiperecogénicos"],"labTests":["MAT: título \u003e1:800 diagnóstico","ELISA IgM: positivo en fase aguda","PCR en orina: positivo primeras 2 semanas","Hemograma: trombocitopenia, leucocitosis","Bioquímica: ALT/AST \u003e500 U/L, creatinina \u003e3.0 mg/dL"],"clinicalExam":"Fiebre 39.5-41°C, ictericia visible en mucosas, hepatomegalia dolorosa, mialgia severa","differentialDiagnosis":["Hepatitis infecciosa canina","Babesiosis","Intoxicación hepática","Pancreatitis aguda"]}, treatment: {"notes":"Chile: VIBRAMYCIN® (Pfizer). ZONA ENDÉMICA: Santiago, Valparaíso, Concepción. ZOONOSIS: handlers deben usar guantes.","duration":"Antibioticoterapia 2-4 semanas. Recuperación renal 2-4 semanas.","emergency":"Fallo renal agudo: fluidoterapia agresiva + diálisis peritoneal si oliguria. TROMBOCITOPENIA: evitar procedimientos invasivos.","firstLine":["Doxiciclina (Vibramycin®) 10 mg/kg PO q12h por 2-4 semanas","Penicilina G cristalina 22,000-44,000 UI/kg IV q6h","Fluidoterapia: Ringer Lactato 60-80 mL/kg/día","Maropitant (Cerenia®) 1-2 mg/kg SC q24h","Famotidina (Pepcid®) 0.5 mg/kg IV q12h"],"secondLine":["Ampicilina 22 mg/kg IV q6h","Ceftriaxona 25-50 mg/kg IV q24h","N-acetilcisteína (Fluimucil®) 140 mg/kg IV carga","Transfusión de plaquetas si \u003c30,000/µL"]}, prevention: ["Vacunación Lepto anual (Nobivac L4 o Leptoguard)","Control de roedores en predios","Evitar contacto con agua stagnante/charcos","Notificación obligatoria al SEREMI de Salud"], prognosis: 'guarded', isZoonotic: true, references: ["ACVIM Consensus Statement Leptospirosis 2023","WSAVA Vaccination Guidelines 2024","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Leucemia-Felina', name: 'Leucemia Felina', scientificName: 'Feline Leukemia Virus (FeLV)', species: 'cat', category: 'infectious', severity: 'severe', description: 'Infección retroviral que causa inmunosupresión, anemia y neoplasias en gatos. Principal causa de muerte en gatos jóvenes.', pathophysiology: 'El virus infecta células de médula ósea y tejido linfático. La inmunosupresión predispone a infecciones secundarias. La integración proviral puede causar transformación neoplásica.', keySigns: ["Pérdida de peso progresiva","Letargia persistente","Anorexia","Fiebre recurrente","Anemia (mucosas pálidas)","Linfadenopatía","Infecciones secundarias frecuentes"], diagnosis: {"imaging":["Radiografía torácica: masas mediastínicas","Ecografía abdominal: linfadenopatía"],"labTests":["ELISA para antígeno p27 (screening)","IFA para confirmar infección persistente","PCR para ADN viral","Hemograma: anemia, leucopenia/leucocitosis"],"clinicalExam":"Pérdida de peso, anemia, linfadenopatía, fiebre, infecciones recurrentes","differentialDiagnosis":["FIV","Toxoplasmosis","Anemia infecciosa felina"]}, treatment: {"notes":"Chile: FeLV test SNAP disponible. Interferón: importación. AZT: farmacias humanas con receta.","duration":"Enfermedad de por vida. Supervivencia variable: meses a años.","emergency":"Shock séptico por inmunosupresión: antibioticoterapia IV + fluidoterapia.","firstLine":["Aislamiento de otros gatos","Soporte nutricional: dieta alta calidad","Antibióticos para infecciones secundarias","Interferón recombinante felino","Antivirales: AZT (Zidovudina) 5 mg/kg PO q12h","Transfusiones si anemia severa"],"secondLine":["Quimioterapia si linfoma (COP o CHOP)","Lomustina"]}, prevention: ["Vacunación: protocolo FeLV a partir de 8-9 semanas","Test FeLV antes de vacunar","Aislamiento de gatos FeLV positivos","Mantener gatos en interiores"], prognosis: 'poor', isZoonotic: false, references: ["AAFP - FeLV Disease Guidelines","Hartmann K, et al. JFMS 2023;25:109895"] },
  { id: 'Neumona-Aspirativa', name: 'Neumonía Aspirativa', scientificName: 'Aspiration Pneumonia', species: 'both', category: 'respiratory', severity: 'severe', description: 'Inflamación e infección pulmonar por aspiración de contenido gástrico.', pathophysiology: 'El contenido ácido gástrico aspirado causa neumonía química. La sobreinfección bacteriana empeora el cuadro. La localización dorso-craneal es más afectada.', keySigns: ["Tos productiva","Disnea","Fiebre","Crepitantes pulmonares","Taquipnea","Mucosas cianóticas","Descarga nasal purulenta","Anorexia"], diagnosis: {"imaging":["Radiografía tórax: infiltrados alveolares en lóbulos dorso-craneales"],"labTests":["Hemograma: leucocitosis","Citología traqueal: neutrófilos + bacterias","Gasometría: hipoxemia"],"clinicalExam":"Fiebre, crepitantes, disnea, taquipnea \u003e40 rpm, mucosas cianóticas","differentialDiagnosis":["Neumonía bacteriana primaria","Neumonía viral","Tumor pulmonar"]}, treatment: {"notes":"Chile: Oxigenoterapia en clínicas de urgencia. Nebulizadores domésticos: accesibles.","duration":"Antibioticoterapia 2-4 semanas. Recuperación radiográfica 4-6 semanas.","emergency":"Fallo respiratorio: oxigenoterapia + oxigenoterapia hiperbárica si disponible.","firstLine":["Antibióticos IV: Ampicilina 22 mg/kg IV q6h + Enrofloxacina 5 mg/kg IV q24h","Oxigenoterapia","Fluidoterapia IV","Nebulización con fisiológico + N-acetilcisteína","Fisioterapia torácica"],"secondLine":["Metronidazol 15 mg/kg IV q12h","Clindamicina 10 mg/kg IV q12h"]}, prevention: ["Alimentación en posición elevada para predisuestos","Evitar anestesia en animales con reflujo","Control de vómitos","Tratar causas subyacentes"], prognosis: 'guarded', isZoonotic: false, references: ["ACVIM Respiratory Consensus 2024","JAVMA 2023;260(S1):S52-S64"] },
  { id: 'Obesidad-Felina', name: 'Obesidad Felina', scientificName: 'Feline Obesity', species: 'cat', category: 'nutritional', severity: 'moderate', description: 'Acumulación excesiva de grasa corporal. Más del 60% de gatos domésticos están con sobrepeso. Predisone a diabetes, enfermedad articular y hepática.', pathophysiology: 'El exceso de tejido adiposo causa inflamación crónica. La resistencia a la insulina predispone a diabetes. La carga articular causa osteoartritis. La lipidosis hepática puede desarrollarse si el gato deja de comer.', keySigns: ["IMC \u003e30% sobre peso ideal","Pérdida de definición de cintura","Grasa palpable sobre costillas","Dificultad para aseo dorsal","Intolerancia al ejercicio","Dolor articular"], diagnosis: {"imaging":[],"labTests":["Hemograma y química: baseline","Glucosa y fructosamina: descartar diabetes"],"clinicalExam":"Evaluación de condición corporal (BCS 1-9). Grasa palpable en zonas características","differentialDiagnosis":["Hipertiroidismo","Diabetes mellitus","Insuficiencia renal"]}, treatment: {"notes":"Chile: Dietas Hills Metabolic, Royal Canin Satiety disponibles.","duration":"Programa de pérdida de peso: 3-6 meses. Mantenimiento de por vida.","emergency":"Lipidosis hepática si anorexia \u003e48h: soporte nutricional urgente.","firstLine":["Dieta de reducción calórica: -20% de mantenimiento","Dieta rica en proteína, baja en carbohidratos","Alimentación fraccionada (3-4 comidas/día)","Ejercicio enriquecido: juguetes interactivos","Pérdida de 1-2% del peso corporal por semana"],"secondLine":["Hills metabolic diet","Péptidos de saciedad"]}, prevention: ["Control de porciones desde cachorro","Ejercicio diario interactivo","Evitar sobras de comida humana","Medir el peso mensualmente"], prognosis: 'good', isZoonotic: false, references: ["AAHA - Weight Management Guidelines 2024","WSAVA Nutritional Assessment Guidelines 2023"] },
  { id: 'Obstruccin-Intestinal', name: 'Obstrucción Intestinal', scientificName: 'Intestinal Obstruction', species: 'both', category: 'gastrointestinal', severity: 'severe', description: 'Obstrucción parcial o completa del lumen intestinal. Emergencia quirúrgica si obstrucción completa.', pathophysiology: 'La obstrucción impide el paso de contenido intestinal. La acumulación de gas y fluido causa distensión. La isquemia puede progresar a necrosis y perforación.', keySigns: ["Vómitos persistentes","Anorexia","Dolor abdominal","Distensión abdominal","Ausencia de heces","Deshidratación","Letargia","Fiebre si necrosis"], diagnosis: {"imaging":["Radiografía abdomen: asas dilatadas con nivel líquido-gas","Ecografía: asas dilatadas"],"labTests":["Hemograma: leucocitosis","Bioquímica: hipercalemia, acidosis","Lactato \u003e4 mmol/L"],"clinicalExam":"Dolor abdominal, distensión, ausencia de ruidos intestinales, deshidratación","differentialDiagnosis":["Pancreatitis","Gastroenteritis","Peritonitis"]}, treatment: {"notes":"Chile: Cirugía de emergencia 24h. Cefazolina genérica. Dieta: Hills i/d, Royal Canin Gastrointestinal.","duration":"Hospitalización 3-5 días. Recuperación 2-3 semanas.","emergency":"Shock séptico por perforación: fluidoterapia + antibióticos IV + cirugía inmediata.","firstLine":["NPO","Fluidoterapia IV: Ringer Lactato 60-80 mL/kg/día","CIRUGÍA DE EMERGENCIA: enteroectomía + anastomosis","Sonda nasogástrica para descompresión","Antibióticos: Cefazolina 22 mg/kg IV q8h","Analgesia: Buprenorfina 0.02 mg/kg IV q6-8h"],"secondLine":["Lavado peritoneal si peritonitis","Nutrición parenteral total"]}, prevention: ["Evitar ingestión de cuerpos extraños","Supervisar paseos","Control de parásitos","Alimentación consistente"], prognosis: 'good', isZoonotic: false, references: ["ACVS Gastrointestinal Surgery Guidelines 2024","JAVMA 2023;260(S1):S52-S64"] },
  { id: 'Peritonitis-Infecciosa-Felina-FIP', name: 'Peritonitis Infecciosa Felina (FIP)', scientificName: 'Feline Coronavirus (FCoV) mutado', species: 'cat', category: 'infectious', severity: 'critical', description: 'Enfermedad inmunomediada causada por mutación del coronavirus felino. Forma húmeda (ascitis) o seca (granulomatosa). Antes 100% mortal, ahora curable con GS-441524.', pathophysiology: 'El FCoV muta a FIPV dentro de macrófagos. Complejos inmunoanticuerpo-antígeno se depositan en vasos sanguíneos causando vasculitis. Esto provoca exudado proteico en cavidades (forma húmeda) o granulomas en órganos (forma seca).', keySigns: ["Fiebre persistente no respondente a antibióticos","Ascitis (forma húmeda)","Pérdida de peso progresiva","Ictericia","Uveítis","Ataxia cerebelar (forma neurológica)"], diagnosis: {"imaging":["Ecografía: ascitis, granulomas hepáticos/renales","Radiografía: efusión pleural"],"labTests":["Rivalta test: positivo","Proteína total \u003e7.5 g/dL con ratio A/G \u003c0.4","AGP \u003e1500 µg/mL","PCR en fluido/tierto positivo para FCoV"],"clinicalExam":"Fiebre 39.5-40.5°C persistente, distensión abdominal, hepatomegalia, esplenomegalia, ictericia","differentialDiagnosis":["Linfoma","Carcinoma","Insuficiencia cardíaca","Peritonitis bacteriana"]}, treatment: {"notes":"Chile: GS-441524 disponible por importación. Famotidina y Prednisolona genéricos disponibles. Pronóstico DRÁSTICAMENTE mejorado desde 2019.","duration":"GS-441524: 84 días. Curación completa en 80-90% de casos.","emergency":"Respiración dificultosa por efusión pleural: toracocentesis de emergencia. Hipoproteinemia severa: albúmina humana 1-2 mL/kg IV lento.","firstLine":["GS-441524 4-6 mg/kg SC q24h por 84 días","Famotidina (Pepcid®) 1 mg/kg PO q12h","Prednisolona 1-2 mg/kg PO q24h tapering","Fluidoterapia subcutánea si deshidratación","Nutrición: dietas de alta densidad calórica"],"secondLine":["GC376 (proteasa inhibitor) 5-10 mg/kg PO q12h","Interferón omega felino 1 MU/kg SC q24h × 5 días","Toceranib (Palladia®) 2-3 mg/kg PO q48h — granulomas refractarios"]}, prevention: ["Aislamiento de gatitos nuevos 14 días mínimo","Higiene estricta en criaderos","Evitar agrupaciones grandes de gatos","Test FCoV antes de integrar gatitos a la colonia"], prognosis: 'guarded', isZoonotic: false, references: ["ISFM FIP Treatment Guidelines 2024","ACVIM Feline FIP Consensus 2023","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Rabies', name: 'Rabies', scientificName: 'Rabies lyssavirus', species: 'both', category: 'infectious', severity: 'critical', description: 'Enfermedad zoonótica mortal causada por virus RNA. Transmisión por mordedura de animal infectado. MORTALIDAD 100% una vez que aparecen síntomas. Notificación obligatoria en Chile.', pathophysiology: 'El virus ingresa por mordedura, viaja por nervios periféricos hasta el sistema nervioso central. Causa encefalitis aguda con destrucción neuronal. No existe tratamiento.', keySigns: ["Agresividad inusual","Hidrofobia","Aerofobia","Espasmos de faringe al tragar","Parálisis mandibular","Salivación excesiva","Ataxia","Convulsiones"], diagnosis: {"imaging":["No hay imagenología diagnóstica en vivo"],"labTests":["IFA en tejido cerebral (post-mortem)","PCR en saliva/secreción faríngea","Negro de Seller en impronta de cerebro"],"clinicalExam":"Cambios neurológicos progresivos: hiperexcitabilidad o parálisis flácida, espasmos de músculos masticadores","differentialDiagnosis":["Encefalitis por Moquillo","Intoxicación","Encefalitis autoinmune","Neoplasia cerebral"]}, treatment: {"notes":"Chile: LEY 20.488 vacunación antirrábica obligatoria para perros. Laboratorio: Instituto de Salud Pública (ISP).","duration":"N/A — enfermedad fatal sin tratamiento.","emergency":"Mordedura de animal sospechoso: lavado herida 15 min con agua y jabón. Profilaxis post-exposición en humano. Notificar a SEREMI de Salud inmediatamente.","firstLine":["NO EXISTE TRATAMIENTO. Enfermedad 100% mortal una vez sintomática.","Eutanasia humanitaria recomendada si se confirma o sospecha fuertemente","Cuarentena estricta 10 días si animal vacunado muerde"],"secondLine":[]}, prevention: ["Vacunación antirrábica obligatoria anual (Ley 20.488)","Mantener vacunación al día en todos los perros","Reportar animales sospechosos a autoridades sanitarias","No manipular animales muertos sin EPP"], prognosis: 'grave', isZoonotic: true, references: ["WHO Rabies Bulletin 2024","OIE/WOAH Rabies Terrestrial Code 2023","Ley 20.488 Chile — Vacunación antirrábica obligatoria","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Reabsorcin-Dental-Felina', name: 'Reabsorción Dental Felina', scientificName: 'Feline Odontoclastic Resorptive Lesions (FORL)', species: 'cat', category: 'dental', severity: 'moderate', description: 'Destrucción progresiva del diente por odontoclastos. Afecta al 28-67% de gatos.', pathophysiology: 'Los odontoclastos activados reabsorben el cemento y la dentina. La lesión comienza en la raíz y progresa hacia la corona. La exposición pulpar causa dolor severo.', keySigns: ["Dolor oral al comer","Babeo","Rechazo de alimento seco","Sangrado de encías","Fractura dental espontánea","Lesiones rosadas en línea de la encía","Halitosis"], diagnosis: {"imaging":["Radiografías dentales intraorales: lesión radiolúcida","Clasificación: Tipo I vs Tipo II"],"labTests":[],"clinicalExam":"Lesiones rosadas en unión cemento-encía, fracturas dentales, sarro","differentialDiagnosis":["Enfermedad periodontal","Fractura dental traumática","Neoplasia oral"]}, treatment: {"notes":"Chile: Cirugía dental veterinaria en clínicas especializadas.","duration":"Extracción: recuperación 7-10 días. Seguimiento dental anual.","emergency":"Dolor severo: analgesia multimodal inmediata.","firstLine":["Extracción dental completa (tratamiento de elección)","Extracción de raíz residual si Tipo II","Analgesia post-operatoria: Buprenorfina + Meloxicam"],"secondLine":["Corona dental (solo Tipo II sin exposición pulpar)"]}, prevention: ["Exámenes dentales anuales con radiografías","Cepillado dental regular","Dieta húmeda reduce estrés mecánico","Detección temprana con radiografías"], prognosis: 'good', isZoonotic: false, references: ["AVDC - FORL Guidelines","Gorrel C. Veterinary Dentistry. Elsevier; 2013"] },
  { id: 'Rinotraquetis-Felina', name: 'Rinotraqueítis Felina', scientificName: 'Feline Herpesvirus-1 (FHV-1)', species: 'cat', category: 'infectious', severity: 'moderate', description: 'Infección viral respiratoria causada por herpesvirus tipo 1. Principal causa de enfermedad respiratoria felina. Infección latente con reactivación.', pathophysiology: 'El virus infecta epitelio respiratorio y conjuntival. La infección latente en ganglios trigemino se reactiva con estrés. La queratitis dendrítica es patognomónica.', keySigns: ["Estornudos frecuentes","Secreción nasal profusa","Conjuntivitis bilateral severa","Queratitis dendrítica","Fiebre","Inapetencia","Úlceras nasales y orales"], diagnosis: {"imaging":[],"labTests":["PCR en hisopo nasal/conjuntival","Citología: células multinucleadas con inclusión intranuclear"],"clinicalExam":"Conjuntivitis severa, queratitis dendrítica, úlceras nasales, blefaroespasmo","differentialDiagnosis":["Calicivirus","Chlamydia felis","Bordetella bronchiseptica","Cuerpo extraño nasal"]}, treatment: {"notes":"Chile: Famciclovir disponible. L-lisina: suplemento disponible.","duration":"Signos agudos: 7-14 días. Portadores latentes: de por vida.","emergency":"Úlceras corneales profundas: oftalmólogo urgente.","firstLine":["Famciclovir 90 mg/kg PO q8-12h (antiviral de elección)","Gotas oculares: Cidofovir tópico q6h","Nebulización con solución salina","Vitaminas del complejo B","Nutrición suave y caliente"],"secondLine":["L-lisina 500 mg PO q12h (controversial)","Interferón omega tópico/ocular"]}, prevention: ["Vacunación intranasal o parenteral","Higiene en guarderías","Reducción de estrés","Aislamiento de gatos enfermos"], prognosis: 'good', isZoonotic: false, references: ["Thiry E, et al. Greene CE, ed. 4th ed. Elsevier; 2012","AAFP/ISFM Feline Respiratory Guidelines 2024"] },
  { id: 'Sndrome-Urolgico-Felino-FLUTD', name: 'Síndrome Urológico Felino (FLUTD)', scientificName: 'Feline Lower Urinary Tract Disease', species: 'cat', category: 'urological', severity: 'severe', description: 'Conjunto de signos del tracto urinario inferior: disuria, estranguria, hematuria. Puede causar obstrucción urinaria (emergencia mortal).', pathophysiology: 'La inflamación de vejiga y uretra causa irritación y obstrucción. Los cristales obstruyen la uretra. La obstrucción causa retención urinaria y falla renal aguda. La hiperpotasemia por retención es mortal.', keySigns: ["Esfuerzo urinario","Orina en pequeñas cantidades","Sangre en orina","Lamido genital","Orina fuera del arenero","Vocalización al orinar","Abdomen distendido (obstrucción)"], diagnosis: {"imaging":["Radiografía: cálculos radiopacos","Ecografía: cálculos, tamaño de vejiga"],"labTests":["Análisis orina: cristales, pH, sangre","Bioquímica: creatinina elevada, potasio \u003e6.5 mEq/L","Urocultivo: descartar infección","Ecografía vejiga: cristales"],"clinicalExam":"Vejiga palpable增大 y firme (obstrucción), dolor al palpar, hematuria, taquicardia (hiperpotasemia)","differentialDiagnosis":["Cistitis bacteriana","Cáncer vejiga","Cistitis intersticial"]}, treatment: {"notes":"Chile: Cystocap disponible. Dietas: Hills c/d, Royal Canin Urinary. Amitriptilina disponible.","duration":"Hospitalización 2-3 días. Dieta urinaria de por vida. Monitoreo pH urinario cada 3 meses.","emergency":"OBSTRUCCIÓN URINARIA: Desobstrucción INMEDIATA + gluconato de calcio IV + fluidoterapia. Hiperpotasemia \u003e6.5 mEq/L es mortal.","firstLine":["Desobstrucción uretral: catéter o lavado retrogrado","Fluidoterapia: Ringer Lactato 60-80 mL/kg/día IV","Gluconato de calcio 10% 0.5-1 mL/kg IV LENTO — hiperpotasemia","Cystocap (N-acetilcisteína) 140 mg/kg carga luego 70 mg/kg q8h"],"secondLine":["Metizol (metenamina) 15 mg/kg PO q12h","Amitriptilina 1-2 mg/kg PO q24h — cistitis idiopática","Gabapentina 5-10 mg/kg PO q8h","Perineostomía (uretrostomía perineal) — obstrucciones recurrentes"]}, prevention: ["Dieta urinaria húmeda (Hills c/d, Royal Canin Urinary)","Fuentes de agua / fuentes para beber","Reducir estrés (ambiente enriquecido)","Areneros limpios y en cantidad","Control de peso"], prognosis: 'guarded', isZoonotic: false, references: ["AAFP/ISFM FLUTD Guidelines 2024","ACVIM Urinary Consensus 2023","Plumb\u0027s Drug Handbook 11th Ed"] },
  { id: 'Toxoplasmosis', name: 'Toxoplasmosis', scientificName: 'Toxoplasma gondii', species: 'cat', category: 'parasitic', severity: 'moderate', description: 'Enfermedad parasitaria causada por el protozoo Toxoplasma gondii. El gato es el hospedador definitivo.', pathophysiology: 'El gato ingiere quistes tisulares. El parásito invade epitelio intestinal produciendo oocistos. La diseminación sistémica alcanza músculos, cerebro y ojos.', keySigns: ["Fiebre","Pérdida de peso","Letargia","Mialgias","Dificultad respiratoria","Signos neurológicos","Ictericia","Uveítis"], diagnosis: {"imaging":["Radiografía torácica si neumonitis","MRI/TC craneal si signos neurológicos"],"labTests":["Serología IgG e IgM","PCR en heces, sangre, LCR","Oocistos en heces (flotación fecal)"],"clinicalExam":"Fiebre, mialgias, neurológicos, uveítis, hepatomegalia","differentialDiagnosis":["FIP","FeLV/FIV","Encefalitis infecciosa","Neoplasia"]}, treatment: {"notes":"Chile: Clindamicina, Doxiciclina disponibles. Zoonosis: gestantes evitar limpiar areneros.","duration":"2-4 semanas de tratamiento.","emergency":"Encefalitis aguda: hospitalización + antibióticos IV.","firstLine":["Clindamicina 12.5-25 mg/kg PO q12h por 2-4 semanas","Doxiciclina 10 mg/kg PO q12h","Trimetoprim-sulfametoxazol 15 mg/kg PO q12h","Soporte nutricional"],"secondLine":["Prednisona si uveítis severa"]}, prevention: ["Cocinar carne thoroughly","Evitar caza cruda","Limpiar arenero diariamente","Lavarse las manos después","Gestantes: evitar limpiar areneros"], prognosis: 'good', isZoonotic: true, references: ["CDC - Toxoplasmosis in Cats","Dubey JP, et al. Greene CE, ed. 4th ed. Elsevier; 2012"] },
  { id: 'Trauma-Torcico', name: 'Trauma Torácico', scientificName: 'Thoracic Trauma', species: 'both', category: 'traumatic', severity: 'severe', description: 'Daño al tórax por impacto directo. Puede causar neumotórax, hemotórax, contusión pulmonar, fracturas costales.', pathophysiology: 'El impacto causa fracturas costales que pueden lacerar pulmón o vasos sanguíneos. El neumotórax colapsa el pulmón. El hemotórax comprime pulmón y causa hipovolemia.', keySigns: ["Disnea","Taquipnea","Respiración superficial","Dolor torácico","Mucosas cianóticas","Hipotermia","Hipotensión","Equimosis en tórax"], diagnosis: {"imaging":["Radiografía tórax: neumotórax, hemotórax, fracturas costales","Ecografía torácica: derrame pleural"],"labTests":["Hemograma: anemia si hemotórax","Gasometría: hipoxemia","Coagulograma: DIC si trauma severo"],"clinicalExam":"Disnea, taquipnea \u003e60 rpm, crepitantes, dolor torácico, mucosas cianóticas","differentialDiagnosis":["Neumonía aspirativa","Insuficiencia cardíaca","Neoplasia torácica"]}, treatment: {"notes":"Chile: Oxigenoterapia en clínicas de urgencia. Toracocentesis: procedimiento estándar.","duration":"Hospitalización 3-7 días. Recuperación 2-4 semanas.","emergency":"Neumotórax a tensión: descompresión con aguja + toracostomía. Shock: fluidoterapia + transfusión.","firstLine":["Oxigenoterapia inmediata","Toracocentesis si neumotórax/hemotórax","Tubo de drenaje pleural si recurrente","Fluidoterapia IV: Ringer Lactato 60-80 mL/kg/día","Analgesia: Buprenorfina 0.02 mg/kg IV q6-8h","Reposo estricto"],"secondLine":["Cirugía: toracotomía si hemorragia activa","Plástia costal si fracturas inestables"]}, prevention: ["Prevención de atropellamientos: correa y arnés","Seguridad en hogares: evitar caídas","Control de agresiones entre perros"], prognosis: 'guarded', isZoonotic: false, references: ["ACVS Small Animal Thoracic Trauma Guidelines 2024","JAVMA 2023;262(12):1420-1432"] },
  { id: 'Virus-de-Inmunodeficiencia-Felina', name: 'Virus de Inmunodeficiencia Felina', scientificName: 'Feline Immunodeficiency Virus (FIV)', species: 'cat', category: 'infectious', severity: 'moderate', description: 'Infección retroviral que causa inmunodeficiencia progresiva similar al VIH. Transmisión principal por mordedura.', pathophysiology: 'El virus infecta linfocitos T CD4+ causando depleción progresiva. La inmunodeficiencia predispone a infecciones secundarias, neoplasias y enfermedades autoinmunes.', keySigns: ["Infecciones recurrentes","Estomatitis crónica","Pérdida de peso","Letargia","Fiebre intermitente","Linfadenopatía","Dermatitis crónica"], diagnosis: {"imaging":["Radiografía dental: reabsorción dental"],"labTests":["ELISA para anticuerpos FIV (screening)","Western Blot para confirmación","PCR para ADN proviral","Hemograma: puede ser normal o leucopenia"],"clinicalExam":"Estomatitis, infecciones recurrentes, linfadenopatía, estado corporal deteriorado","differentialDiagnosis":["FeLV","Enfermedad dental primaria","Estomatitis"]}, treatment: {"notes":"Chile: Test FIV SNAP disponible. AZT: farmacias. Cirugía dental: clínicas especializadas.","duration":"Manejo de por vida. Fase latente puede durar años.","emergency":"Infección oportunista severa: hospitalización + antibióticos IV.","firstLine":["Manejo de infecciones secundarias","Antibióticos según cultivo","Alimentación de alta calidad","Antivirales: AZT 5 mg/kg PO q12h","Tratamiento de estomatitis: poliquimioterapia","Interferón omega recombinante"],"secondLine":["Extracción dental agresiva para estomatitis","Corticoides tópicos bucales"]}, prevention: ["No hay vacuna","Mantener gatos en interiores","Castrar machos","Test FIV antes de integrar nuevos gatos","Evitar contacto con gatos callejeros"], prognosis: 'guarded', isZoonotic: false, references: ["AAFP - FIV Testing Guidelines","Levy J, et al. JFMS 2023;25:110123"] },];
